LAST_ACTIVATION_TIME = None
ACTIVATION_WINDOW = timedelta(seconds=0.03)

LAST_HEARTBEAT = datetime.now()
HEARTBEAT_TIMEOUT = timedelta(seconds=777)
RESTARTING = False
heartbeat_task = None 

# ====================
# Activation Control
# ====================
async def activate_symbol(symbol):
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, INACTIVE_SYMBOL, ACTIVATION_CANDIDATES, LAST_ACTIVATION_TIME    
    try:
        if not GLOBAL_SEQUENCE_ACTIVE:
            current_time = datetime.now()
            if LAST_ACTIVATION_TIME is None or (current_time - LAST_ACTIVATION_TIME) > ACTIVATION_WINDOW:
                ACTIVATION_CANDIDATES = []
            if symbol not in ACTIVATION_CANDIDATES:
                ACTIVATION_CANDIDATES.append(symbol)
                LAST_ACTIVATION_TIME = current_time
                print(f"{symbol} added to activation candidates: {ACTIVATION_CANDIDATES}")
            if len(ACTIVATION_CANDIDATES) > 0:
                GLOBAL_SEQUENCE_ACTIVE = True
                ACTIVE_SYMBOL = random.choice(ACTIVATION_CANDIDATES)
                INACTIVE_SYMBOL = [s for s in CONFIG["SYMBOLS"] if s != ACTIVE_SYMBOL]
                ACTIVATION_CANDIDATES = []
                print(f"{ACTIVE_SYMBOL} has been randomly selected as the active symbol.")
    except Exception as e:
        await reset_state()
        return False


# ====================
# Deactivation Control
# ====================
async def deactivate_symbol(symbol):
    global GLOBAL_SEQUENCE_ACTIVE, LAST_ACTIVATION_TIME
    current_time = datetime.now()
    if LAST_ACTIVATION_TIME is not None and GLOBAL_SEQUENCE_ACTIVE:
        elapsed_time = current_time - LAST_ACTIVATION_TIME
        if elapsed_time >= timedelta(seconds=777):        
            print(f"{symbol}: Active sequence compromised. Possible arbitrage...Pay your attention and start monitoring your data_flow in order to expose intentional data_integrity violation from your broker...Releasing global lock and if it keeps happening...think about giving up the actual account because it might have been flagged...restart in 3 seconds.")
            await reset_state() 
            await asyncio.sleep(3)  


# ====================
# HeartBeat Monitor
# ====================
async def heartbeat_monitor():
    """Monitor for missed heartbeats and restart the bot if needed."""
    global LAST_HEARTBEAT, RESTARTING
    while True:
        await asyncio.sleep(33)
        now = datetime.now()
        if now - LAST_HEARTBEAT > HEARTBEAT_TIMEOUT:
            print(f"No heartbeat received for over 333 seconds. Possible arbitrage...Pay your attention and start monitoring your data_flow in order to expose intentional data_integrity violation from your broker...Fresh restarting the bot after 3 seconds and if it keeps happening...think about giving up the actual account because it might have been flagged.")
            RESTARTING = True
            await reset_state()
            os.execl(sys.executable, sys.executable, *sys.argv)
            
 
