def create_subscription_callback4(symbol):
    def callback(data):
        try:
            if "tick" in data:
                asyncio.ensure_future(handle_tick4(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick4(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT4"]
    try:
        await asyncio.sleep(random.uniform(0.01, 0.1))
    
        quote = tick["tick"]["quote"]

        if state["skip_next_tick4"] > 0:
            if state["skip_next_tick4"] == 1:
                print(f"{symbol}: Skipped tick {quote} - stored as first tick of new candle")
                state["current_candle_ticks4"] = [quote]
                state["skip_next_tick4"] = 0  
            return  
            
        if len(state["current_candle_ticks4"]) < CONFIG["CANDLE_DURATION4"] + 1:
            state["current_candle_ticks4"].append(quote)
            
        if len(state["current_candle_ticks4"]) == CONFIG["CANDLE_DURATION4"] + 1:
            print(f"{symbol}: Candle complete: {state['current_candle_ticks4']}")
            async with SYMBOL_LOCKS[symbol]:
                await process_candle4(symbol)
            state["skip_next_tick4"] = 1
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_reversals4(symbol, last_candle_color4, second_last_candle_color4):
    """Detect isolated single reversals and update counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT4"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT4"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        current_reversal4 = (
            second_last_candle_color4 is not None and
            last_candle_color4 is not None and
            last_candle_color4 != second_last_candle_color4
        )

        if current_reversal4:
            state["reversal_count4"] += 1
            state["was_previous_reversal4"] = True
            print(f"{symbol}: Reversal detected. Count: {state['reversal_count4']}")

            if not state["is_sequence_starting_with_green4"] and not state["is_sequence_starting_with_red4"]:
                if second_last_candle_color4 == -1:
                    state["is_sequence_starting_with_green4"] = True
                    print(f"{symbol}: Green flag triggered")
                elif second_last_candle_color4 == 1:
                    state["is_sequence_starting_with_red4"] = True
                    print(f"{symbol}: Red flag triggered")

        else:
            if state["was_previous_reversal4"]:
                if state["reversal_count4"] == 1:
                    state["isolated_single_reversal_count4"] += 1
                    print(f"{symbol}: Isolated single reversal confirmed. Total: {state['isolated_single_reversal_count4']}")
                    if state["isolated_single_reversal_count4"] >= 21:  # The threshold can still be increased for safety 
                        ACTIVE_BOT = "BOT4"
                        INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                        await activate_symbol(symbol)

                else:
                    prev_count4 = state["isolated_single_reversal_count4"]
                    state["isolated_single_reversal_count4"] = 0
                    if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count4 >= 21:  # The threshold can still be increased for safety 
                        print(f"{symbol}: Active sequence completed (had {prev_count4} isolated single reversals). Releasing global lock")
                        await reset_state()

            state["was_previous_reversal4"] = False
            state["reversal_count4"] = 0
            state["is_sequence_starting_with_green4"] = False
            state["is_sequence_starting_with_red4"] = False
            print(f"Reversal count reset for {symbol}")

    except Exception as e:
        print(f"Error detecting reversals for {symbol}: {e}")


async def process_candle4(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL 
    state = SYMBOL_STATES[symbol]["BOT4"]
    try:
        second_last_candle_color4 = (
            1 if state["last_candle_open4"] is not None and state["last_candle_close4"] is not None and state["last_candle_close4"] > state["last_candle_open4"] else
            (-1 if state["last_candle_open4"] is not None and state["last_candle_close4"] is not None and state["last_candle_close4"] < state["last_candle_open4"] else None)
        )
        last_candle_color4 = (
            1 if state["current_candle_ticks4"][0] is not None and state["current_candle_ticks4"][-1] > state["current_candle_ticks4"][0] else
            (-1 if state["current_candle_ticks4"][0] is not None and state["current_candle_ticks4"][-1] < state["current_candle_ticks4"][0] else None)
        )

        await detect_reversals4(symbol, last_candle_color4, second_last_candle_color4)

        if state["reversal_count4"] == 1:
            if state["isolated_single_reversal_count4"] == 21:  # The threshold can still be increased for safety 
                if state["is_sequence_starting_with_green4"]:
                    state["trade_type4"] = "PUTE"
                    state["stake_amount4"] = 1
                    state["previous_stake_amount4"] = state["stake_amount4"]
                elif state["is_sequence_starting_with_red4"]:
                    state["trade_type4"] = "CALLE"
                    state["stake_amount4"] = 1
                    state["previous_stake_amount4"] = state["stake_amount4"]

            elif state["isolated_single_reversal_count4"] > 21:  # The threshold can still be increased for safety 
                if state["is_sequence_starting_with_green4"]:
                    state["trade_type4"] = "PUTE"
                    state["stake_amount4"] = state["previous_stake_amount4"] * 2.1
                    state["previous_stake_amount4"] = state["stake_amount4"]
                elif state["is_sequence_starting_with_red4"]:
                    state["trade_type4"] = "CALLE"
                    state["stake_amount4"] = state["previous_stake_amount4"] * 2.1
                    state["previous_stake_amount4"] = state["stake_amount4"]
                    
        else:
            state["trade_type4"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type4"] in ["PUTE", "CALLE"] and
            state["stake_amount4"] > 0 and
            state["isolated_single_reversal_count4"] > state["last_executed_reversal_count4"]
        ):
            await place_trades4(symbol, state["trade_type4"], state["stake_amount4"])
            print(f"Placed {state['trade_type4']} trade for {symbol} with stake: {state['stake_amount4']}")
            state["last_executed_reversal_count4"] = state["isolated_single_reversal_count4"]
        else:
            print(f"No trade placed for {symbol} (duplicate or invalid reversal count)")

        state["last_candle_open4"] = state["current_candle_ticks4"][0]
        state["last_candle_close4"] = state["current_candle_ticks4"][-1]

    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


async def place_trades4(symbol, trade_type4, stake_amount4):
    """Place trades using trade API."""
    try:
        proposal = await api.proposal({
            "proposal": 1,
            "amount": stake_amount4,
            "basis": "stake",
            "contract_type": trade_type4,
            "currency": "USD",
            "duration": 1,
            "duration_unit": "t",
            "symbol": symbol
        })
    except APIError as e:
        print(f"APIError while getting proposal for {symbol}: {e}. Skipping trade...")
        return
    except Exception as e:
        print(f"Unexpected error while getting proposal for {symbol}: {e}. Skipping trade...")
        return
        
    try:
        proposal_id = proposal.get("proposal", {}).get("id")
        if not proposal_id:
            print(f"No proposal ID found for {symbol}. Skipping trade...")
            return
        buy_response = await api.buy({
            "buy": proposal_id,
            "price": stake_amount4
        })
        print(f"Trade successfully placed for {symbol}")      
    except APIError as e:
        print(f"APIError while buying contract for {symbol}: {e}. Skipping trade...")
    except Exception as e:
        print(f"Unexpected error while buying contract for {symbol}: {e}. Skipping trade...")
        

