async def reset_state7():
    """Reset internal state for all symbols."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, INACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT, ACTIVATION_CANDIDATES, LAST_ACTIVATION_TIME
    try:
        for symbol in SYMBOL_STATES:
            state = SYMBOL_STATES[symbol]["BOT7"]
            state["last_candle_open7"] = None
            state["last_candle_close7"] = None
            state["current_candle_ticks7"] = []
            state["non_reversal_count7"] = 0
            state["is_sequence_starting_with_green7"] = False
            state["is_sequence_starting_with_red7"] = False
            state["trade_type7"] = ""
            state["stake_amount7"] = 0
            state["previous_stake_amount7"] = 0
            state["skip_next_tick7"] = 0 
            state["last_executed_non_reversal_count7"] = -1
            state["isolated_single_non_reversal_count7"] = 0
            state["was_previous_non_reversal7"] = False
        GLOBAL_SEQUENCE_ACTIVE = False
        ACTIVE_SYMBOL = None
        ACTIVE_BOT = None
        INACTIVE_SYMBOL = None
        INACTIVE_BOT = None
        ACTIVATION_CANDIDATES = []
        LAST_ACTIVATION_TIME = None
        print("Bot7 state has been reset for all symbols.")
    except Exception as e:
        print(f"Error during reset_state7: {e}")


def create_subscription_callback7(symbol):
    def callback(data):
        try:
            if "tick" in data:
                asyncio.ensure_future(handle_tick7(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick7(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT7"]
    try: 
        if symbol in ["stpRNG", "stpRNG2", "stpRNG3", "stpRNG4", "stpRNG5"]:
            print(f"{symbol}: Ignored due to insufficient payout.")  
        else:
            await asyncio.sleep(random.uniform(0.01, 0.1))
        
            quote = tick["tick"]["quote"]

            if state["skip_next_tick7"] > 0:
                if state["skip_next_tick7"] == 1:
                    print(f"{symbol}: Skipped tick {quote} - stored as first tick of new candle")
                    state["current_candle_ticks7"] = [quote]
                    state["skip_next_tick7"] = 0  
                return  

            if len(state["current_candle_ticks7"]) < CONFIG["CANDLE_DURATION7"] + 1:
                state["current_candle_ticks7"].append(quote)

            if len(state["current_candle_ticks7"]) == CONFIG["CANDLE_DURATION7"] + 1:
                print(f"{symbol}: Candle complete: {state['current_candle_ticks7']}")
                async with SYMBOL_LOCKS[symbol]:
                    await process_candle7(symbol)
                state["skip_next_tick7"] = 1
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_non_reversals7(symbol, last_candle_color7, second_last_candle_color7):
    """Detect isolated single non reversals and update counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT7"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT7"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        current_non_reversal7 = (
            second_last_candle_color7 is not None and
            last_candle_color7 is not None and
            last_candle_color7 == second_last_candle_color7
        )

        if current_non_reversal7:
            state["non_reversal_count7"] += 1
            state["was_previous_non_reversal7"] = True
            print(f"{symbol}: Non reversal detected. Count: {state['non_reversal_count7']}")

            if not state["is_sequence_starting_with_green7"] and not state["is_sequence_starting_with_red7"]:
                if second_last_candle_color7 == 1:
                    state["is_sequence_starting_with_green7"] = True
                    print(f"{symbol}: Green flag triggered")
                elif second_last_candle_color7 == -1:
                    state["is_sequence_starting_with_red7"] = True
                    print(f"{symbol}: Red flag triggered")

        else:
            if state["was_previous_non_reversal7"]:
                if state["non_reversal_count7"] == 1:
                    state["isolated_single_non_reversal_count7"] += 1
                    print(f"{symbol}: Isolated single non reversal confirmed. Total: {state['isolated_single_non_reversal_count7']}")
                    
                    if state["isolated_single_non_reversal_count7"] >= 21:
                        ACTIVE_BOT = "BOT7"
                        INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                        await activate_symbol(symbol)

                else:
                    prev_count7 = state["isolated_single_non_reversal_count7"]
                    state["isolated_single_non_reversal_count7"] = 0

                    if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count7 >= 21:
                        print(f"{symbol}: Active sequence completed (had {prev_count7} isolated single non reversals). Releasing global lock")
                        await reset_state()

            state["was_previous_non_reversal7"] = False
            state["non_reversal_count7"] = 0
            state["is_sequence_starting_with_green7"] = False
            state["is_sequence_starting_with_red7"] = False

    except Exception as e:
        print(f"Error detecting non reversals for {symbol}: {e}")         


