async def process_candle9(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL
    state = SYMBOL_STATES[symbol]["BOT9"]
    try:
        second_last_candle_color9 = (
            1 if state["last_candle_open9"] is not None and state["last_candle_close9"] is not None and state["last_candle_close9"] > state["last_candle_open9"] else
            (-1 if state["last_candle_open9"] is not None and state["last_candle_close9"] is not None and state["last_candle_close9"] < state["last_candle_open9"] else None)
        )
        last_candle_color9 = (
            1 if state["current_candle_ticks9"][0] is not None and state["current_candle_ticks9"][-1] > state["current_candle_ticks9"][0] else
            (-1 if state["current_candle_ticks9"][0] is not None and state["current_candle_ticks9"][-1] < state["current_candle_ticks9"][0] else None)
        )
      
        await detect_non_reversals9(symbol, last_candle_color9, second_last_candle_color9)
       
        if state["non_reversal_count9"] == 21:
            if state["is_sequence_starting_with_green9"]:
                state["trade_type9"] = "PUTE"
                state["stake_amount9"] = 1
                state["previous_stake_amount9"] = state["stake_amount9"]
            elif state["is_sequence_starting_with_red9"]:
                state["trade_type9"] = "CALLE"
                state["stake_amount9"] = 1
                state["previous_stake_amount9"] = state["stake_amount9"]
                
        elif state["non_reversal_count9"] > 21:
            if state["is_sequence_starting_with_green9"]:
                state["trade_type9"] = "PUTE"
                state["stake_amount9"] = state["previous_stake_amount9"] * 2.1
                state["previous_stake_amount9"] = state["stake_amount9"]
            elif state["is_sequence_starting_with_red9"]:
                state["trade_type9"] = "CALLE"
                state["stake_amount9"] = state["previous_stake_amount9"] * 2.1
                state["previous_stake_amount9"] = state["stake_amount9"]
                
        else:
            state["trade_type9"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type9"] in ["PUTE", "CALLE"] and
            state["stake_amount9"] > 0 and
            state["non_reversal_count9"] > state["last_executed_non_reversal_count9"]
        ):
            await place_trades9(symbol, state["trade_type9"], state["stake_amount9"])
            print(f"Placed {state['trade_type9']} trade for {symbol} with stake: {state['stake_amount9']}")
            state["last_executed_non_reversal_count9"] = state["non_reversal_count9"]
        else:
            print(f"No trade placed for {symbol} (duplicate or invalid non_reversal count)")

        state["last_candle_open9"] = state["current_candle_ticks9"][0]
        state["last_candle_close9"] = state["current_candle_ticks9"][-1]
        
    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


