async def handle_tick12(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT12"]
    try:
        await asyncio.sleep(random.uniform(0.01, 0.1))    
    
        quote = tick["tick"]["quote"]

        if state["skip_next_tick12"] > 0:
            if state["skip_next_tick12"] == 1:
                print(f"{symbol}: Skipped tick {quote} - stored as first tick of new candle")
                state["current_candle_ticks12"] = [quote]
                state["skip_next_tick12"] = 0  
            return  
            
        if len(state["current_candle_ticks12"]) < CONFIG["CANDLE_DURATION12"] + 1:
            state["current_candle_ticks12"].append(quote)
            
        if len(state["current_candle_ticks12"]) == CONFIG["CANDLE_DURATION12"] + 1:
            print(f"{symbol}: Candle complete: {state['current_candle_ticks12']}")
            async with SYMBOL_LOCKS[symbol]:
                await process_candle12(symbol)
            state["skip_next_tick12"] = 1
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_reversals12(symbol, last_candle_color12, second_last_candle_color12):
    """Detect isolated multiple reversals and update counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT12"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT12"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        current_reversal12 = (
            second_last_candle_color12 is not None and
            last_candle_color12 is not None and
            last_candle_color12 != second_last_candle_color12
        )

        if current_reversal12:
            state["reversal_count12"] += 1
            state["was_previous_reversal12"] = True
            print(f"{symbol}: Reversal detected. Count: {state['reversal_count12']}")

            if not state["is_sequence_starting_with_green12"] and not state["is_sequence_starting_with_red12"]:
                if second_last_candle_color12 == -1:
                    state["is_sequence_starting_with_green12"] = True
                    print(f"{symbol}: Green flag triggered")
                elif second_last_candle_color12 == 1:
                    state["is_sequence_starting_with_red12"] = True
                    print(f"{symbol}: Red flag triggered")

        else:
            if state["was_previous_reversal12"]:
                if state["reversal_count12"] > 1:
                    state["isolated_multiple_reversal_count12"] += 1
                    print(f"{symbol}: Isolated multiple reversal confirmed. Total: {state['isolated_multiple_reversal_count12']}")
                   
                    if state["isolated_multiple_reversal_count12"] >= 21:  # The threshold can still be increased for safety 
                        ACTIVE_BOT = "BOT12"
                        INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                        await activate_symbol(symbol)

                else:
                    prev_count12 = state["isolated_multiple_reversal_count12"]
                    state["isolated_multiple_reversal_count12"] = 0
                    if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count12 >= 21:  # The threshold can still be increased for safety 
                        print(f"{symbol}: Active sequence completed (had {prev_count12} isolated multiple reversals). Releasing lock")
                        await reset_state()

            state["was_previous_reversal12"] = False
            state["reversal_count12"] = 0
            state["is_sequence_starting_with_green12"] = False
            state["is_sequence_starting_with_red12"] = False
            print(f"Reversal count reset for {symbol}")

    except Exception as e:
        print(f"Error detecting reversals for {symbol}: {e}")


