def create_subscription_callback17(symbol):
    def callback(data):
        try:
            if "tick" in data:
                asyncio.ensure_future(handle_tick17(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick17(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT17"]
    try:
        await asyncio.sleep(random.uniform(0.01, 0.1))
            
        quote = tick["tick"]["quote"]

        if state["skip_next_tick17"] > 0:
            if state["skip_next_tick17"] == 1:
                print(f"{symbol}: Skipped tick {quote} - stored as first tick of new candle")
                state["current_candle_ticks17"] = [quote]
                state["skip_next_tick17"] = 0  
            return  
            
        if len(state["current_candle_ticks17"]) < CONFIG["CANDLE_DURATION17"] + 1:
            state["current_candle_ticks17"].append(quote)

        if len(state["current_candle_ticks17"]) == CONFIG["CANDLE_DURATION17"] + 1:
            print(f"{symbol}: Candle complete: {state['current_candle_ticks17']}")
            async with SYMBOL_LOCKS[symbol]:
                await process_candle17(symbol)
            state["skip_next_tick17"] = 1
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_non_reversals17(symbol, last_candle_color17, second_last_candle_color17):
    """Detect isolated multiple non reversals and update counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT17"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT17"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        current_non_reversal17 = (
            second_last_candle_color17 is not None and
            last_candle_color17 is not None and
            last_candle_color17 == second_last_candle_color17
        )

        if current_non_reversal17:
            state["non_reversal_count17"] += 1
            state["was_previous_non_reversal17"] = True
            print(f"{symbol}: Non reversal detected. Count: {state['non_reversal_count17']}")

            if not state["is_sequence_starting_with_green17"] and not state["is_sequence_starting_with_red17"]:
                if second_last_candle_color17 == 1:
                    state["is_sequence_starting_with_green17"] = True
                    print(f"{symbol}: Green flag triggered")
                elif second_last_candle_color17 == -1:
                    state["is_sequence_starting_with_red17"] = True
                    print(f"{symbol}: Red flag triggered")

        else:
            if state["was_previous_non_reversal17"]:
                if state["non_reversal_count17"] > 1:
                    state["isolated_multiple_non_reversal_count17"] += 1
                    print(f"{symbol}: Isolated multiple non reversal confirmed. Total: {state['isolated_multiple_non_reversal_count17']}")
                   
                    if state["isolated_multiple_non_reversal_count17"] >= 21:
                        ACTIVE_BOT = "BOT17"
                        INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                        await activate_symbol(symbol)

                else:
                    prev_count17 = state["isolated_multiple_non_reversal_count17"]
                    state["isolated_multiple_non_reversal_count17"] = 0

                    if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count17 >= 21:
                        print(f"{symbol}: Active sequence completed (had {prev_count17} isolated multiple non reversals). Releasing lock")
                        await reset_state()

            state["was_previous_non_reversal17"] = False
            state["non_reversal_count17"] = 0
            state["is_sequence_starting_with_green17"] = False
            state["is_sequence_starting_with_red17"] = False

    except Exception as e:
        print(f"Error detecting non reversals for {symbol}: {e}")         


