async def detect_reversals22(symbol, last_candle_color22, second_last_candle_color22):
    """Detect reversals and update reversal counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT22"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT22"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        if (
            second_last_candle_color22 is None
            or last_candle_color22 is None
            or last_candle_color22 == second_last_candle_color22
        ):
            prev_count22 = state["reversal_count22"]
            state["reversal_count22"] = 0
            state["is_sequence_starting_with_green22"] = False
            state["is_sequence_starting_with_red22"] = False
            print(f"Reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count22 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count22} reversals). Releasing global lock")
                await reset_state()
            return

        if not state["is_sequence_starting_with_green22"] and not state["is_sequence_starting_with_red22"]:
            if second_last_candle_color22 == -1:
                state["is_sequence_starting_with_green22"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color22 == 1:
                state["is_sequence_starting_with_red22"] = True
                print(f"{symbol}: Red flag triggered")

        if last_candle_color22 != second_last_candle_color22:
            if state["is_sequence_starting_with_green22"] or state["is_sequence_starting_with_red22"]:
                state["reversal_count22"] += 1
                print(f"{symbol}: Reversal count increased to {state['reversal_count22']}")
                if state["reversal_count22"] >= 21:
                    ACTIVE_BOT = "BOT22"
                    INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                    await activate_symbol(symbol)

    except Exception as e:
        print(f"Error detecting reversals for {symbol}: {e}")


async def process_candle22(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL 
    state = SYMBOL_STATES[symbol]["BOT22"]
    try:
        second_last_candle_color22 = (
            1 if state["last_candle_open22"] is not None and state["last_candle_close22"] is not None and state["last_candle_close22"] > state["last_candle_open22"] else
            (-1 if state["last_candle_open22"] is not None and state["last_candle_close22"] is not None and state["last_candle_close22"] < state["last_candle_open22"] else None)
        )
        last_candle_color22 = (
            1 if state["current_candle_ticks22"][0] is not None and state["current_candle_ticks22"][-1] > state["current_candle_ticks22"][0] else
            (-1 if state["current_candle_ticks22"][0] is not None and state["current_candle_ticks22"][-1] < state["current_candle_ticks22"][0] else None)
        )

        await detect_reversals22(symbol, last_candle_color22, second_last_candle_color22)

        if state["reversal_count22"] == 21:
            if state["is_sequence_starting_with_green22"]:
                state["trade_type22"] = "CALLE"
                state["stake_amount22"] = 1
                state["previous_stake_amount22"] = state["stake_amount22"]
            elif state["is_sequence_starting_with_red22"]:
                state["trade_type22"] = "PUTE"
                state["stake_amount22"] = 1
                state["previous_stake_amount22"] = state["stake_amount22"]
                
        elif state["reversal_count22"] > 21:
            if state["is_sequence_starting_with_green22"]:
                state["trade_type22"] = "CALLE" if state["reversal_count22"] % 2 == 1 else "PUTE"
                state["stake_amount22"] = state["previous_stake_amount22"] * 2.1
                state["previous_stake_amount22"] = state["stake_amount22"]
            elif state["is_sequence_starting_with_red22"]:
                state["trade_type22"] = "PUTE" if state["reversal_count22"] % 2 == 1 else "CALLE"
                state["stake_amount22"] = state["previous_stake_amount22"] * 2.1
                state["previous_stake_amount22"] = state["stake_amount22"]
                
        else:
            state["trade_type22"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type22"] in ["PUTE", "CALLE"] and
            state["stake_amount22"] > 0 and
            state["reversal_count22"] > state["last_executed_reversal_count22"]
        ):
            await place_trades22(symbol, state["trade_type22"], state["stake_amount22"])
            print(f"Placed {state['trade_type22']} trade for {symbol} with stake: {state['stake_amount22']}")
            state["last_executed_reversal_count22"] = state["reversal_count22"]
        else:
            print(f"No trade placed for {symbol} (duplicate or invalid reversal count)")

        state["last_candle_open22"] = state["current_candle_ticks22"][0]
        state["last_candle_close22"] = state["current_candle_ticks22"][-1]

    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


