def create_subscription_callback25(symbol):
    def callback(data):
        try:        
            if "tick" in data:
                asyncio.ensure_future(handle_tick25(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick25(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT25"]
    try: 
        if symbol in ["stpRNG", "stpRNG2", "stpRNG3", "stpRNG4", "stpRNG5"]:
            print(f"{symbol}: Ignored due to insufficient payout.")
        else: 
            await asyncio.sleep(random.uniform(0.01, 0.1))
                
            quote = tick["tick"]["quote"]

            if state["skip_next_tick25"] > 0:
                if state["skip_next_tick25"] == 1:
                    print(f"{symbol}: Skipped tick {quote} - stored as first tick of new candle")
                    state["current_candle_ticks25"] = [quote]
                    state["skip_next_tick25"] = 0  
                return  
            
            if len(state["current_candle_ticks25"]) < CONFIG["CANDLE_DURATION25"] + 1:
                state["current_candle_ticks25"].append(quote)
            
            if len(state["current_candle_ticks25"]) == CONFIG["CANDLE_DURATION25"] + 1:
                print(f"{symbol}: Candle complete: {state['current_candle_ticks25']}")
                async with SYMBOL_LOCKS[symbol]:
                    await process_candle25(symbol)
                state["skip_next_tick25"] = 1
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_non_reversals25(symbol, last_candle_color25, second_last_candle_color25):
    """Detect isolated multiple non reversals and update counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT25"]
    try:                
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT25"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        current_non_reversal25 = (
            second_last_candle_color25 is not None and
            last_candle_color25 is not None and
            last_candle_color25 == second_last_candle_color25
        )

        if current_non_reversal25:
            state["non_reversal_count25"] += 1
            state["was_previous_non_reversal25"] = True
            print(f"{symbol}: Non reversal detected. Count: {state['non_reversal_count25']}")

            if not state["is_sequence_starting_with_green25"] and not state["is_sequence_starting_with_red25"]:
                if second_last_candle_color25 == 1:
                    state["is_sequence_starting_with_green25"] = True
                    print(f"{symbol}: Green flag triggered")
                elif second_last_candle_color25 == -1:
                    state["is_sequence_starting_with_red25"] = True
                    print(f"{symbol}: Red flag triggered")

        else:
            if state["was_previous_non_reversal25"]:
                if state["non_reversal_count25"] > 1:
                    state["isolated_multiple_non_reversal_count25"] += 1
                    print(f"{symbol}: Isolated multiple non reversal confirmed. Total: {state['isolated_multiple_non_reversal_count25']}")
                   
                    if state["isolated_multiple_non_reversal_count25"] >= 21:
                        ACTIVE_BOT = "BOT25"
                        INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                        await activate_symbol(symbol)

                else:
                    prev_count25 = state["isolated_multiple_non_reversal_count25"]
                    state["isolated_multiple_non_reversal_count25"] = 0

                    if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count25 >= 21:
                        print(f"{symbol}: Active sequence completed (had {prev_count25} isolated multiple non reversals). Releasing lock")
                        await reset_state()

            state["was_previous_non_reversal25"] = False
            state["non_reversal_count25"] = 0
            state["is_sequence_starting_with_green25"] = False
            state["is_sequence_starting_with_red25"] = False

    except Exception as e:
        print(f"Error detecting non reversals for {symbol}: {e}")         


