            if state["is_sequence_starting_with_green35"]:
                state["trade_type35"] = "PUTE"
                state["stake_amount35"] = state["previous_stake_amount35"] * 2.1
                state["previous_stake_amount35"] = state["stake_amount35"]
            elif state["is_sequence_starting_with_red35"]:
                state["trade_type35"] = "CALLE"
                state["stake_amount35"] = state["previous_stake_amount35"] * 2.1
                state["previous_stake_amount35"] = state["stake_amount35"]
                
