def create_subscription_callback40(symbol):
    def callback(data):
        try:
            if "tick" in data:
                asyncio.ensure_future(handle_tick40(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick40(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT40"]
    try: 
        if symbol in ["stpRNG", "stpRNG2", "stpRNG3", "stpRNG4", "stpRNG5"]:
            print(f"{symbol}: Ignored due to insufficient payout.")
        else: 
            await asyncio.sleep(random.uniform(0.01, 0.1))
                
            quote = tick["tick"]["quote"]

            if state["skip_next_tick40"] > 0:
                if state["skip_next_tick40"] == 1:
                    print(f"{symbol}: Skipped tick {quote} - stored as first tick of new candle")
                    state["current_candle_ticks40"] = [quote]
                    state["skip_next_tick40"] = 0  
                return  
            
            if len(state["current_candle_ticks40"]) < CONFIG["CANDLE_DURATION40"] + 1:
                state["current_candle_ticks40"].append(quote)
            
            if len(state["current_candle_ticks40"]) == CONFIG["CANDLE_DURATION40"] + 1:
                print(f"{symbol}: Candle complete: {state['current_candle_ticks40']}")
                async with SYMBOL_LOCKS[symbol]:
                    await process_candle40(symbol)
                state["skip_next_tick40"] = 1
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_reversals40(symbol, last_candle_color40, second_last_candle_color40):
    """Detect reversals and update reversal counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT40"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT40"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        if (
            second_last_candle_color40 is None
            or last_candle_color40 is None
            or last_candle_color40 == second_last_candle_color40
        ):
            prev_count40 = state["reversal_count40"]
            state["reversal_count40"] = 0
            state["is_sequence_starting_with_green40"] = False
            state["is_sequence_starting_with_red40"] = False
            print(f"Reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count40 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count40} reversals). Releasing global lock")
                await reset_state()
            return

        if not state["is_sequence_starting_with_green40"] and not state["is_sequence_starting_with_red40"]:
            if second_last_candle_color40 == -1:
                state["is_sequence_starting_with_green40"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color40 == 1:
                state["is_sequence_starting_with_red40"] = True
                print(f"{symbol}: Red flag triggered")

        if last_candle_color40 != second_last_candle_color40:
            if state["is_sequence_starting_with_green40"] or state["is_sequence_starting_with_red40"]:
                state["reversal_count40"] += 1
                print(f"{symbol}: Reversal count increased to {state['reversal_count40']}")
                if state["reversal_count40"] >= 21:
                    ACTIVE_BOT = "BOT40"
                    INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                    await activate_symbol(symbol)

    except Exception as e:
        print(f"Error detecting reversals for {symbol}: {e}")


async def process_candle40(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL
    state = SYMBOL_STATES[symbol]["BOT40"]
    try:
        second_last_candle_color40 = (
            1 if state["last_candle_open40"] is not None and state["last_candle_close40"] is not None and state["last_candle_close40"] > state["last_candle_open40"] else
            (-1 if state["last_candle_open40"] is not None and state["last_candle_close40"] is not None and state["last_candle_close40"] < state["last_candle_open40"] else None)
        )
        last_candle_color40 = (
            1 if state["current_candle_ticks40"][0] is not None and state["current_candle_ticks40"][-1] > state["current_candle_ticks40"][0] else
            (-1 if state["current_candle_ticks40"][0] is not None and state["current_candle_ticks40"][-1] < state["current_candle_ticks40"][0] else None)
        )

        await detect_reversals40(symbol, last_candle_color40, second_last_candle_color40)

        if state["reversal_count40"] == 21:
            if state["is_sequence_starting_with_green40"]:
                state["trade_type40"] = "CALLE"
                state["stake_amount40"] = 1
                state["previous_stake_amount40"] = state["stake_amount40"]
            elif state["is_sequence_starting_with_red40"]:
                state["trade_type40"] = "PUTE"
                state["stake_amount40"] = 1 
                state["previous_stake_amount40"] = state["stake_amount40"]
                
        elif state["reversal_count40"] > 21:
            if state["is_sequence_starting_with_green40"]:
                state["trade_type40"] = "CALLE" if state["reversal_count40"] % 2 == 1 else "PUTE"
                state["stake_amount40"] = state["previous_stake_amount40"] * 2.1
                state["previous_stake_amount40"] = state["stake_amount40"]
            elif state["is_sequence_starting_with_red40"]:
                state["trade_type40"] = "PUTE" if state["reversal_count40"] % 2 == 1 else "CALLE"
                state["stake_amount40"] = state["previous_stake_amount40"] * 2.1
                state["previous_stake_amount40"] = state["stake_amount40"]
                
        else:
            state["trade_type40"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type40"] in ["PUTE", "CALLE"] and
            state["stake_amount40"] > 0 and
            state["reversal_count40"] > state["last_executed_reversal_count40"]
        ):
            await place_trades40(symbol, state["trade_type40"], state["stake_amount40"])
            print(f"Placed {state['trade_type40']} trade for {symbol} with stake: {state['stake_amount40']}")
            state["last_executed_reversal_count40"] = state["reversal_count40"]
        else:
            print(f"No trade placed for {symbol} (duplicate or invalid reversal count)")

        state["last_candle_open40"] = state["current_candle_ticks40"][0]
        state["last_candle_close40"] = state["current_candle_ticks40"][-1]

    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


async def place_trades40(symbol, trade_type40, stake_amount40):
    """Place trades using trade API."""
    try:   
        proposal = await api.proposal({
            "proposal": 1,
            "amount": stake_amount40,
            "basis": "stake",
            "contract_type": trade_type40,
            "currency": "USD",
            "duration": 10,
            "duration_unit": "t",
            "symbol": symbol
        })
    except APIError as e:
        print(f"APIError while getting proposal for {symbol}: {e}. Skipping trade...")
        return
    except Exception as e:
        print(f"Unexpected error while getting proposal for {symbol}: {e}. Skipping trade...")
        return
        
    try:
        proposal_id = proposal.get("proposal", {}).get("id")
        if not proposal_id:
            print(f"No proposal ID found for {symbol}. Skipping trade...")
            return
        buy_response = await api.buy({
            "buy": proposal_id,
            "price": stake_amount40
        })
        print(f"Trade successfully placed via for {symbol} ({trade_type40}, ${stake_amount40})") 
    except APIError as e:
        print(f"APIError while buying contract for {symbol}: {e}. Skipping trade...")
    except Exception as e:
        print(f"Unexpected error while buying contract for {symbol}: {e}. Skipping trade...") 
        
 
