async def handle_tick41(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT41"]
    try:
    
        quote = tick["tick"]["quote"]
        
        if state["skip_next_ticks41"] > 0:
            if state["skip_next_ticks41"] == 2:
                print(f"{symbol}: First skipped tick {quote} - trade placement point")
                if state["pending_trade41"] is not None:
                    trade_type = state["pending_trade41"]["trade_type"]
                    stake_amount = state["pending_trade41"]["stake_amount"]
                    print(f"{symbol}: Executing pending trade - {trade_type} with stake {stake_amount}")
                    await place_trades41(symbol, trade_type, stake_amount)
                    state["pending_trade41"] = None
                state["current_candle_ticks41"] = [quote]
                state["skip_next_ticks41"] = 1 
            elif state["skip_next_ticks41"] == 1:
                print(f"{symbol}: Second skipped tick {quote} - stored as first tick of new candle")
                state["current_candle_ticks41"] = [quote]
                state["skip_next_ticks41"] = 0 
            return
            
        if len(state["current_candle_ticks41"]) < CONFIG["CANDLE_DURATION41"] + 1:
            state["current_candle_ticks41"].append(quote)
            
        if len(state["current_candle_ticks41"]) == CONFIG["CANDLE_DURATION41"] + 1:
            print(f"{symbol}: Candle complete: {state['current_candle_ticks41']}")
            async with SYMBOL_LOCKS[symbol]:
                await process_candle41(symbol)
            state["skip_next_ticks41"] = 2                
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


