async def detect_non_reversals47(symbol, last_candle_color47, second_last_candle_color47):
    """Detect isolated single non reversals and update counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT47"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT47"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        current_non_reversal47 = (
            second_last_candle_color47 is not None and
            last_candle_color47 is not None and
            last_candle_color47 == second_last_candle_color47
        )

        if current_non_reversal47:
            state["non_reversal_count47"] += 1
            state["was_previous_non_reversal47"] = True
            print(f"{symbol}: Non reversal detected. Count: {state['non_reversal_count47']}")

            if not state["is_sequence_starting_with_green47"] and not state["is_sequence_starting_with_red47"]:
                if second_last_candle_color47 == 1:
                    state["is_sequence_starting_with_green47"] = True
                    print(f"{symbol}: Green flag triggered")
                elif second_last_candle_color47 == -1:
                    state["is_sequence_starting_with_red47"] = True
                    print(f"{symbol}: Red flag triggered")

        else:
            if state["was_previous_non_reversal47"]:
                if state["non_reversal_count47"] == 1:
                    state["isolated_single_non_reversal_count47"] += 1
                    print(f"{symbol}: Isolated single non reversal confirmed. Total: {state['isolated_single_non_reversal_count47']}")
                    
                    if state["isolated_single_non_reversal_count47"] >= 21:
                        ACTIVE_BOT = "BOT47"
                        INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                        await activate_symbol(symbol)

                else:
                    prev_count47 = state["isolated_single_non_reversal_count47"]
                    state["isolated_single_non_reversal_count47"] = 0

                    if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count47 >= 21:
                        print(f"{symbol}: Active sequence completed (had {prev_count47} isolated single non reversals). Releasing global lock")
                        await reset_state()

            state["was_previous_non_reversal47"] = False
            state["non_reversal_count47"] = 0
            state["is_sequence_starting_with_green47"] = False
            state["is_sequence_starting_with_red47"] = False

    except Exception as e:
        print(f"Error detecting non reversals for {symbol}: {e}")         


async def process_candle47(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL 
    state = SYMBOL_STATES[symbol]["BOT47"]
    try:
        second_last_candle_color47 = (
            1 if state["last_candle_open47"] is not None and state["last_candle_close47"] is not None and state["last_candle_close47"] > state["last_candle_open47"] else
            (-1 if state["last_candle_open47"] is not None and state["last_candle_close47"] is not None and state["last_candle_close47"] < state["last_candle_open47"] else None)
        )
        last_candle_color47 = (
            1 if state["current_candle_ticks47"][0] is not None and state["current_candle_ticks47"][-1] > state["current_candle_ticks47"][0] else
            (-1 if state["current_candle_ticks47"][0] is not None and state["current_candle_ticks47"][-1] < state["current_candle_ticks47"][0] else None)
        )

        await detect_non_reversals47(symbol, last_candle_color47, second_last_candle_color47)
       
        if state["non_reversal_count47"] == 1:
            if state["isolated_single_non_reversal_count47"] == 21:
                if state["is_sequence_starting_with_green47"]:
                    state["trade_type47"] = "CALLE"
                    state["stake_amount47"] = 1
                    state["previous_stake_amount47"] = state["stake_amount47"]
                elif state["is_sequence_starting_with_red47"]:
                    state["trade_type47"] = "PUTE"
                    state["stake_amount47"] = 1
                    state["previous_stake_amount47"] = state["stake_amount47"]    
                    
            elif state["isolated_single_non_reversal_count47"] > 21:            
                if state["is_sequence_starting_with_green47"]:
                    state["trade_type47"] = "CALLE"
                    state["stake_amount47"] = state["previous_stake_amount47"] * 2.1
                    state["previous_stake_amount47"] = state["stake_amount47"]
                elif state["is_sequence_starting_with_red47"]:
                    state["trade_type47"] = "PUTE"
                    state["stake_amount47"] = state["previous_stake_amount47"] * 2.1
                    state["previous_stake_amount47"] = state["stake_amount47"]

        else:
            state["trade_type47"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type47"] in ["PUTE", "CALLE"] and
            state["stake_amount47"] > 0 and
            state["isolated_single_non_reversal_count47"] > state["last_executed_non_reversal_count47"]
        ):
            state["pending_trade47"] = {
                "trade_type": state["trade_type47"],
                "stake_amount": state["stake_amount47"]
            }
            state["last_executed_non_reversal_count47"] = state["isolated_single_non_reversal_count47"]
            print(f"Trade prepared for {symbol}: {state['trade_type47']} with stake: {state['stake_amount47']} (isolated_single_non_reversal_count: {state['isolated_single_non_reversal_count47']})")
        else:
            print(f"No trade prepared for {symbol} (trade_type: {state['trade_type47']}, stake: {state['stake_amount47']}, isolated_single_non_reversal_count: {state['isolated_single_non_reversal_count47']})")

        state["last_candle_open47"] = state["current_candle_ticks47"][0]
        state["last_candle_close47"] = state["current_candle_ticks47"][-1]

    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


async def place_trades47(symbol, trade_type47, stake_amount47):
    """Place trades using trade API."""
    try:
        proposal = await api.proposal({
            "proposal": 1,
            "amount": stake_amount47,
            "basis": "stake",
            "contract_type": trade_type47,
            "currency": "USD",
            "duration": 2,
            "duration_unit": "t",
            "symbol": symbol
        })
    except APIError as e:
        print(f"APIError while getting proposal for {symbol}: {e}. Skipping trade...")
        return
    except Exception as e:
        print(f"Unexpected error while getting proposal for {symbol}: {e}. Skipping trade...")
        return
    try:
        proposal_id = proposal.get("proposal", {}).get("id")
        if not proposal_id:
            print(f"No proposal ID found for {symbol}. Skipping trade...")
            return
        buy_response = await api.buy({
            "buy": proposal_id,
            "price": stake_amount47
        })
        print(f"Trade successfully placed via for {symbol} ({trade_type47}, ${stake_amount47})")          
    except APIError as e:
        print(f"APIError while buying contract for {symbol}: {e}. Skipping trade...")
    except Exception as e:
        print(f"Unexpected error while buying contract for {symbol}: {e}. Skipping trade...")
        

