async def reset_state49():
    """Reset internal state for all symbols."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, INACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT, ACTIVATION_CANDIDATES, LAST_ACTIVATION_TIME
    try:
        for symbol in SYMBOL_STATES:
            state = SYMBOL_STATES[symbol]["BOT49"]
            state["last_candle_open49"] = None
            state["last_candle_close49"] = None
            state["current_candle_ticks49"] = []
            state["non_reversal_count49"] = 0
            state["is_sequence_starting_with_green49"] = False
            state["is_sequence_starting_with_red49"] = False
            state["trade_type49"] = ""
            state["stake_amount49"] = 0
            state["previous_stake_amount49"] = 0
            state["skip_next_ticks49"] = 0 
            state["last_executed_non_reversal_count49"] = -1
            state["pending_trade49"] = None 
        GLOBAL_SEQUENCE_ACTIVE = False
        ACTIVE_SYMBOL = None
        ACTIVE_BOT = None
        INACTIVE_SYMBOL = None
        INACTIVE_BOT = None
        ACTIVATION_CANDIDATES = []
        LAST_ACTIVATION_TIME = None
        print("Bot49 state has been reset for all symbols.")
    except Exception as e:
        print(f"Error during reset_state49: {e}")


def create_subscription_callback49(symbol):
    def callback(data):
        try:
            if "tick" in data:
                asyncio.ensure_future(handle_tick49(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick49(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT49"]
    try:
        
        quote = tick["tick"]["quote"]
        
        if state["skip_next_ticks49"] > 0:
            if state["skip_next_ticks49"] == 2:
                print(f"{symbol}: First skipped tick {quote} - trade placement point")
                if state["pending_trade49"] is not None:
                    trade_type = state["pending_trade49"]["trade_type"]
                    stake_amount = state["pending_trade49"]["stake_amount"]
                    print(f"{symbol}: Executing pending trade - {trade_type} with stake {stake_amount}")
                    await place_trades49(symbol, trade_type, stake_amount)
                    state["pending_trade49"] = None
                state["current_candle_ticks49"] = [quote]
                state["skip_next_ticks49"] = 1  
            elif state["skip_next_ticks49"] == 1:
                print(f"{symbol}: Second skipped tick {quote} - stored as first tick of new candle")
                state["current_candle_ticks49"] = [quote]
                state["skip_next_ticks49"] = 0  
            return          
            
        if len(state["current_candle_ticks49"]) < CONFIG["CANDLE_DURATION49"] + 1:
            state["current_candle_ticks49"].append(quote)
            
        if len(state["current_candle_ticks49"]) == CONFIG["CANDLE_DURATION49"] + 1:
            print(f"{symbol}: Candle complete: {state['current_candle_ticks49']}")
            async with SYMBOL_LOCKS[symbol]:
                await process_candle49(symbol)
            state["skip_next_ticks49"] = 2 
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_non_reversals49(symbol, last_candle_color49, second_last_candle_color49):
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT49"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT49"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return
            
        if (
            second_last_candle_color49 is None
            or last_candle_color49 is None
            or last_candle_color49 != second_last_candle_color49
        ):
            prev_count49 = state["non_reversal_count49"]
            state["non_reversal_count49"] = 0
            state["is_sequence_starting_with_green49"] = False
            state["is_sequence_starting_with_red49"] = False
            print(f"Non_reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count49 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count49} non_reversals). Releasing global lock")
                await reset_state()
            return
        
        if not state["is_sequence_starting_with_green49"] and not state["is_sequence_starting_with_red49"]:
            if second_last_candle_color49 == 1:
                state["is_sequence_starting_with_green49"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color49 == -1:
                state["is_sequence_starting_with_red49"] = True
                print(f"{symbol}: Red flag triggered")
       
        if last_candle_color49 == second_last_candle_color49:
            if state["is_sequence_starting_with_green49"] or state["is_sequence_starting_with_red49"]:
                state["non_reversal_count49"] += 1
                print(f"{symbol}: Non_reversal count increased to {state['non_reversal_count49']}")
                if state["non_reversal_count49"] >= 21:
                    ACTIVE_BOT = "BOT49"
                    INACTIVE_BOT = [b for b in CONFIG["BOTS"] if b != ACTIVE_BOT]
                    await activate_symbol(symbol)
    
    except Exception as e:
        print(f"Error detecting non_reversals for {symbol}: {e}")


async def process_candle49(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL
    state = SYMBOL_STATES[symbol]["BOT49"]
    try:
        second_last_candle_color49 = (
            1 if state["last_candle_open49"] is not None and state["last_candle_close49"] is not None and state["last_candle_close49"] > state["last_candle_open49"] else
            (-1 if state["last_candle_open49"] is not None and state["last_candle_close49"] is not None and state["last_candle_close49"] < state["last_candle_open49"] else None)
        )
        last_candle_color49 = (
            1 if state["current_candle_ticks49"][0] is not None and state["current_candle_ticks49"][-1] > state["current_candle_ticks49"][0] else
            (-1 if state["current_candle_ticks49"][0] is not None and state["current_candle_ticks49"][-1] < state["current_candle_ticks49"][0] else None)
        )
      
        await detect_non_reversals49(symbol, last_candle_color49, second_last_candle_color49)
       
        if state["non_reversal_count49"] == 21:
            if state["is_sequence_starting_with_green49"]:
                state["trade_type49"] = "PUTE"
                state["stake_amount49"] = 1
                state["previous_stake_amount49"] = state["stake_amount49"]
            elif state["is_sequence_starting_with_red49"]:
                state["trade_type49"] = "CALLE"
                state["stake_amount49"] = 1
                state["previous_stake_amount49"] = state["stake_amount49"]
                
        elif state["non_reversal_count49"] > 21:
            if state["is_sequence_starting_with_green49"]:
                state["trade_type49"] = "PUTE"
                state["stake_amount49"] = state["previous_stake_amount49"] * 2.1
                state["previous_stake_amount49"] = state["stake_amount49"]
            elif state["is_sequence_starting_with_red49"]:
                state["trade_type49"] = "CALLE"
                state["stake_amount49"] = state["previous_stake_amount49"] * 2.1
                state["previous_stake_amount49"] = state["stake_amount49"]
                
        else:
            state["trade_type49"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type49"] in ["PUTE", "CALLE"] and
            state["stake_amount49"] > 0 and
            state["non_reversal_count49"] > state["last_executed_non_reversal_count49"]
        ):
            state["pending_trade49"] = {
                "trade_type": state["trade_type49"],
                "stake_amount": state["stake_amount49"]
            }
            state["last_executed_non_reversal_count49"] = state["non_reversal_count49"]
            print(f"Trade prepared for {symbol}: {state['trade_type49']} with stake: {state['stake_amount49']} (non_reversal_count: {state['non_reversal_count49']})")
        else:
            print(f"No trade prepared for {symbol} (trade_type: {state['trade_type49']}, stake: {state['stake_amount49']}, non_reversal_count: {state['non_reversal_count49']})")         
            
        state["last_candle_open49"] = state["current_candle_ticks49"][0]
        state["last_candle_close49"] = state["current_candle_ticks49"][-1]
        
    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


async def place_trades49(symbol, trade_type49, stake_amount49):
    """Place trades using trade API."""
    try:
        proposal = await api.proposal({
            "proposal": 1,
            "amount": stake_amount49,
            "basis": "stake",
            "contract_type": trade_type49,
            "currency": "USD",
            "duration": 3,
            "duration_unit": "t",
            "symbol": symbol
        })
    except APIError as e:
        print(f"APIError while getting proposal for {symbol}: {e}. Skipping trade...")
        return
    except Exception as e:
        print(f"Unexpected error while getting proposal for {symbol}: {e}. Skipping trade...")
        return
        
    try:
        proposal_id = proposal.get("proposal", {}).get("id")
        if not proposal_id:
            print(f"No proposal ID found for {symbol}. Skipping trade...")
            return
        buy_response = await api.buy({
            "buy": proposal_id,
            "price": stake_amount49
        })
        print(f"Trade successfully placed via for {symbol} ({trade_type49}, ${stake_amount49})")  
    except APIError as e:
        print(f"APIError while buying contract for {symbol}: {e}. Skipping trade...")
    except Exception as e:
        print(f"Unexpected error while buying contract for {symbol}: {e}. Skipping trade...")


