async def detect_non_reversals51(symbol, last_candle_color51, second_last_candle_color51):
    """Detect isolated multiple non reversals and update counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT51"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT51"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        current_non_reversal51 = (
            second_last_candle_color51 is not None and
            last_candle_color51 is not None and
            last_candle_color51 == second_last_candle_color51
        )

        if current_non_reversal51:
            state["non_reversal_count51"] += 1
            state["was_previous_non_reversal51"] = True
            print(f"{symbol}: Non reversal detected. Count: {state['non_reversal_count51']}")

            if not state["is_sequence_starting_with_green51"] and not state["is_sequence_starting_with_red51"]:
                if second_last_candle_color51 == 1:
                    state["is_sequence_starting_with_green51"] = True
                    print(f"{symbol}: Green flag triggered")
                elif second_last_candle_color51 == -1:
                    state["is_sequence_starting_with_red51"] = True
                    print(f"{symbol}: Red flag triggered")

        else:
            if state["was_previous_non_reversal51"]:
                if state["non_reversal_count51"] > 1:
                    state["isolated_multiple_non_reversal_count51"] += 1
                    print(f"{symbol}: Isolated multiple non reversal confirmed. Total: {state['isolated_multiple_non_reversal_count51']}")
                   
                    if state["isolated_multiple_non_reversal_count51"] >= 21:
                        ACTIVE_BOT = "BOT51"
                        INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                        await activate_symbol(symbol)

                else:
                    prev_count51 = state["isolated_multiple_non_reversal_count51"]
                    state["isolated_multiple_non_reversal_count51"] = 0

                    if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count51 >= 21:
                        print(f"{symbol}: Active sequence completed (had {prev_count51} isolated multiple non reversals). Releasing lock")
                        await reset_state()

            state["was_previous_non_reversal51"] = False
            state["non_reversal_count51"] = 0
            state["is_sequence_starting_with_green51"] = False
            state["is_sequence_starting_with_red51"] = False

    except Exception as e:
        print(f"Error detecting non reversals for {symbol}: {e}")         


