            state["last_candle_close57"] = None
            state["current_candle_ticks57"] = []
            state["non_reversal_count57"] = 0
            state["is_sequence_starting_with_green57"] = False
            state["is_sequence_starting_with_red57"] = False
            state["trade_type57"] = ""
            state["stake_amount57"] = 0
            state["previous_stake_amount57"] = 0
            state["last_executed_non_reversal_count57"] = -1
            state["isolated_multiple_non_reversal_count57"] = 0
