async def detect_non_reversals59(symbol, last_candle_color59, second_last_candle_color59):
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT59"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT59"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return
            
        if (
            second_last_candle_color59 is None
            or last_candle_color59 is None
            or last_candle_color59 != second_last_candle_color59
        ):
            prev_count59 = state["non_reversal_count59"]
            state["non_reversal_count59"] = 0
            state["is_sequence_starting_with_green59"] = False
            state["is_sequence_starting_with_red59"] = False
            print(f"Non_reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count59 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count59} non_reversals). Releasing global lock")
                await reset_state()
            return
        
        if not state["is_sequence_starting_with_green59"] and not state["is_sequence_starting_with_red59"]:
            if second_last_candle_color59 == 1:
                state["is_sequence_starting_with_green59"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color59 == -1:
                state["is_sequence_starting_with_red59"] = True
                print(f"{symbol}: Red flag triggered")
       
        if last_candle_color59 == second_last_candle_color59:
            if state["is_sequence_starting_with_green59"] or state["is_sequence_starting_with_red59"]:
                state["non_reversal_count59"] += 1
                print(f"{symbol}: Non_reversal count increased to {state['non_reversal_count59']}")
                if state["non_reversal_count59"] >= 21:
                    ACTIVE_BOT = "BOT59"
                    INACTIVE_BOT = [b for b in CONFIG["BOTS"] if b != ACTIVE_BOT]
                    await activate_symbol(symbol)
    
    except Exception as e:
        print(f"Error detecting non_reversals for {symbol}: {e}")


async def process_candle59(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL
    state = SYMBOL_STATES[symbol]["BOT59"]
    try:
        second_last_candle_color59 = (
            1 if state["last_candle_open59"] is not None and state["last_candle_close59"] is not None and state["last_candle_close59"] > state["last_candle_open59"] else
            (-1 if state["last_candle_open59"] is not None and state["last_candle_close59"] is not None and state["last_candle_close59"] < state["last_candle_open59"] else None)
        )
        last_candle_color59 = (
            1 if state["current_candle_ticks59"][0] is not None and state["current_candle_ticks59"][-1] > state["current_candle_ticks59"][0] else
            (-1 if state["current_candle_ticks59"][0] is not None and state["current_candle_ticks59"][-1] < state["current_candle_ticks59"][0] else None)
        )
      
        await detect_non_reversals59(symbol, last_candle_color59, second_last_candle_color59)
       
        if state["non_reversal_count59"] == 21:
            if state["is_sequence_starting_with_green59"]:
                state["trade_type59"] = "PUTE"
                state["stake_amount59"] = 1
                state["previous_stake_amount59"] = state["stake_amount59"]
            elif state["is_sequence_starting_with_red59"]:
                state["trade_type59"] = "CALLE"
                state["stake_amount59"] = 1
                state["previous_stake_amount59"] = state["stake_amount59"]
                
        elif state["non_reversal_count59"] > 21:
            if state["is_sequence_starting_with_green59"]:
                state["trade_type59"] = "PUTE"
                state["stake_amount59"] = state["previous_stake_amount59"] * 2.1
                state["previous_stake_amount59"] = state["stake_amount59"]
            elif state["is_sequence_starting_with_red59"]:
                state["trade_type59"] = "CALLE"
                state["stake_amount59"] = state["previous_stake_amount59"] * 2.1
                state["previous_stake_amount59"] = state["stake_amount59"]
                
        else:
            state["trade_type59"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type59"] in ["PUTE", "CALLE"] and
            state["stake_amount59"] > 0 and
            state["non_reversal_count59"] > state["last_executed_non_reversal_count59"]
        ):
            state["pending_trade59"] = {
                "trade_type": state["trade_type59"],
                "stake_amount": state["stake_amount59"]
            }
            state["last_executed_non_reversal_count59"] = state["non_reversal_count59"]
            print(f"Trade prepared for {symbol}: {state['trade_type59']} with stake: {state['stake_amount59']} (non_reversal_count: {state['non_reversal_count59']})")
        else:
            print(f"No trade prepared for {symbol} (trade_type: {state['trade_type59']}, stake: {state['stake_amount59']}, non_reversal_count: {state['non_reversal_count59']})")

        state["last_candle_open59"] = state["current_candle_ticks59"][0]
        state["last_candle_close59"] = state["current_candle_ticks59"][-1]
        
    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


async def place_trades59(symbol, trade_type59, stake_amount59):
    """Place trades using trade API."""
    try:
        proposal = await api.proposal({
            "proposal": 1,
            "amount": stake_amount59,
            "basis": "stake",
            "contract_type": trade_type59,
            "currency": "USD",
            "duration": 4,
            "duration_unit": "t",
            "symbol": symbol
        })
    except APIError as e:
        print(f"APIError while getting proposal for {symbol}: {e}. Skipping trade...")
        return
    except Exception as e:
        print(f"Unexpected error while getting proposal for {symbol}: {e}. Skipping trade...")
        return
        
    try:
        proposal_id = proposal.get("proposal", {}).get("id")
        if not proposal_id:
            print(f"No proposal ID found for {symbol}. Skipping trade...")
            return
        buy_response = await api.buy({
            "buy": proposal_id,
            "price": stake_amount59
        })
        print(f"Trade successfully placed via for {symbol} ({trade_type59}, ${stake_amount59})")         
    except APIError as e:
        print(f"APIError while buying contract for {symbol}: {e}. Skipping trade...")
    except Exception as e:
        print(f"Unexpected error while buying contract for {symbol}: {e}. Skipping trade...")


