async def reset_state62():
    """Reset internal state for all symbols."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, INACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT, ACTIVATION_CANDIDATES, LAST_ACTIVATION_TIME
    try:
        for symbol in SYMBOL_STATES:
            state = SYMBOL_STATES[symbol]["BOT62"]
            state["last_candle_open62"] = None
            state["last_candle_close62"] = None
            state["current_candle_ticks62"] = []
            state["reversal_count62"] = 0
            state["is_sequence_starting_with_green62"] = False
            state["is_sequence_starting_with_red62"] = False
            state["trade_type62"] = ""
            state["stake_amount62"] = 0
            state["previous_stake_amount62"] = 0
            state["last_executed_reversal_count62"] = -1
            state["skip_next_ticks62"] = 0
            state["pending_trade62"] = None             
        GLOBAL_SEQUENCE_ACTIVE = False
        ACTIVE_SYMBOL = None
        ACTIVE_BOT = None
        INACTIVE_SYMBOL = None
        INACTIVE_BOT = None
        ACTIVATION_CANDIDATES = []
        LAST_ACTIVATION_TIME = None
        print("Bot62 state has been reset for all symbols.")
    except Exception as e:
        print(f"Error during reset_state62: {e}")


def create_subscription_callback62(symbol):
    def callback(data):
        try:
            if "tick" in data:
                asyncio.ensure_future(handle_tick62(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick62(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT62"]
    try:
        
        quote = tick["tick"]["quote"]
        
        if state["skip_next_ticks62"] > 0:
            if state["skip_next_ticks62"] == 2:
                print(f"{symbol}: First skipped tick {quote} - trade placement point")
                if state["pending_trade62"] is not None:
                    trade_type = state["pending_trade62"]["trade_type"]
                    stake_amount = state["pending_trade62"]["stake_amount"]
                    print(f"{symbol}: Executing pending trade - {trade_type} with stake {stake_amount}")
                    await place_trades62(symbol, trade_type, stake_amount)
                    state["pending_trade62"] = None
                state["current_candle_ticks62"] = [quote]
                state["skip_next_ticks62"] = 1  
            elif state["skip_next_ticks62"] == 1:
                print(f"{symbol}: Second skipped tick {quote} - stored as first tick of new candle")
                state["current_candle_ticks62"] = [quote]
                state["skip_next_ticks62"] = 0  
            return
            
        if len(state["current_candle_ticks62"]) < CONFIG["CANDLE_DURATION62"] + 1:
            state["current_candle_ticks62"].append(quote)
            
        if len(state["current_candle_ticks62"]) == CONFIG["CANDLE_DURATION62"] + 1:
            print(f"{symbol}: Candle complete: {state['current_candle_ticks62']}")
            async with SYMBOL_LOCKS[symbol]:
                await process_candle62(symbol)
            state["skip_next_ticks62"] = 2 
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_reversals62(symbol, last_candle_color62, second_last_candle_color62):
    """Detect reversals and update reversal counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT62"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT62"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        if (
            second_last_candle_color62 is None
            or last_candle_color62 is None
            or last_candle_color62 == second_last_candle_color62
        ):
            prev_count62 = state["reversal_count62"]
            state["reversal_count62"] = 0
            state["is_sequence_starting_with_green62"] = False
            state["is_sequence_starting_with_red62"] = False
            print(f"Reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count62 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count62} reversals). Releasing global lock")
                await reset_state()
            return

        if not state["is_sequence_starting_with_green62"] and not state["is_sequence_starting_with_red62"]:
            if second_last_candle_color62 == -1:
                state["is_sequence_starting_with_green62"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color62 == 1:
                state["is_sequence_starting_with_red62"] = True
                print(f"{symbol}: Red flag triggered")

        if last_candle_color62 != second_last_candle_color62:
            if state["is_sequence_starting_with_green62"] or state["is_sequence_starting_with_red62"]:
                state["reversal_count62"] += 1
                print(f"{symbol}: Reversal count increased to {state['reversal_count62']}")
                if state["reversal_count62"] >= 21:
                    ACTIVE_BOT = "BOT62"
                    INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                    await activate_symbol(symbol)

    except Exception as e:
        print(f"Error detecting reversals for {symbol}: {e}")


async def process_candle62(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL 
    state = SYMBOL_STATES[symbol]["BOT62"]
    try:
        second_last_candle_color62 = (
            1 if state["last_candle_open62"] is not None and state["last_candle_close62"] is not None and state["last_candle_close62"] > state["last_candle_open62"] else
            (-1 if state["last_candle_open62"] is not None and state["last_candle_close62"] is not None and state["last_candle_close62"] < state["last_candle_open62"] else None)
        )
        last_candle_color62 = (
            1 if state["current_candle_ticks62"][0] is not None and state["current_candle_ticks62"][-1] > state["current_candle_ticks62"][0] else
            (-1 if state["current_candle_ticks62"][0] is not None and state["current_candle_ticks62"][-1] < state["current_candle_ticks62"][0] else None)
        )

        await detect_reversals62(symbol, last_candle_color62, second_last_candle_color62)

        if state["reversal_count62"] == 21:
            if state["is_sequence_starting_with_green62"]:
                state["trade_type62"] = "CALLE"
                state["stake_amount62"] = 1
                state["previous_stake_amount62"] = state["stake_amount62"]
            elif state["is_sequence_starting_with_red62"]:
                state["trade_type62"] = "PUTE"
                state["stake_amount62"] = 1
                state["previous_stake_amount62"] = state["stake_amount62"]
                
        elif state["reversal_count62"] > 21:
            if state["is_sequence_starting_with_green62"]:
                state["trade_type62"] = "CALLE" if state["reversal_count62"] % 2 == 1 else "PUTE"
                state["stake_amount62"] = state["previous_stake_amount62"] * 2.1
                state["previous_stake_amount62"] = state["stake_amount62"]
            elif state["is_sequence_starting_with_red62"]:
                state["trade_type62"] = "PUTE" if state["reversal_count62"] % 2 == 1 else "CALLE"
                state["stake_amount62"] = state["previous_stake_amount62"] * 2.1
                state["previous_stake_amount62"] = state["stake_amount62"]
                
        else:
            state["trade_type62"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type62"] in ["PUTE", "CALLE"] and
            state["stake_amount62"] > 0 and
            state["reversal_count62"] > state["last_executed_reversal_count62"]
        ):
            state["pending_trade62"] = {
                "trade_type": state["trade_type62"],
                "stake_amount": state["stake_amount62"]
            }
            state["last_executed_reversal_count62"] = state["reversal_count62"]
            print(f"Trade prepared for {symbol}: {state['trade_type62']} with stake: {state['stake_amount62']} (reversal_count: {state['reversal_count62']})")
        else:
            print(f"No trade prepared for {symbol} (trade_type: {state['trade_type62']}, stake: {state['stake_amount62']}, reversal_count: {state['reversal_count62']})")

        state["last_candle_open62"] = state["current_candle_ticks62"][0]
        state["last_candle_close62"] = state["current_candle_ticks62"][-1]

    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


