async def detect_non_reversals63(symbol, last_candle_color63, second_last_candle_color63):
    """Detect isolated single non reversals and update counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT63"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT63"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        current_non_reversal63 = (
            second_last_candle_color63 is not None and
            last_candle_color63 is not None and
            last_candle_color63 == second_last_candle_color63
        )

        if current_non_reversal63:
            state["non_reversal_count63"] += 1
            state["was_previous_non_reversal63"] = True
            print(f"{symbol}: Non reversal detected. Count: {state['non_reversal_count63']}")

            if not state["is_sequence_starting_with_green63"] and not state["is_sequence_starting_with_red63"]:
                if second_last_candle_color63 == 1:
                    state["is_sequence_starting_with_green63"] = True
                    print(f"{symbol}: Green flag triggered")
                elif second_last_candle_color63 == -1:
                    state["is_sequence_starting_with_red63"] = True
                    print(f"{symbol}: Red flag triggered")

        else:
            if state["was_previous_non_reversal63"]:
                if state["non_reversal_count63"] == 1:
                    state["isolated_single_non_reversal_count63"] += 1
                    print(f"{symbol}: Isolated single non reversal confirmed. Total: {state['isolated_single_non_reversal_count63']}")
                    
                    if state["isolated_single_non_reversal_count63"] >= 21:
                        ACTIVE_BOT = "BOT63"
                        INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                        await activate_symbol(symbol)

                else:
                    prev_count63 = state["isolated_single_non_reversal_count63"]
                    state["isolated_single_non_reversal_count63"] = 0

                    if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count63 >= 21:
                        print(f"{symbol}: Active sequence completed (had {prev_count63} isolated single non reversals).Releasing lock")
                        await reset_state()

            state["was_previous_non_reversal63"] = False
            state["non_reversal_count63"] = 0
            state["is_sequence_starting_with_green63"] = False
            state["is_sequence_starting_with_red63"] = False

    except Exception as e:
        print(f"Error detecting non reversals for {symbol}: {e}")         


