def create_subscription_callback64(symbol):
    def callback(data):
        try:  
            if "tick" in data:
                asyncio.ensure_future(handle_tick64(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick64(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT64"]
    try: 
        if symbol in ["stpRNG", "stpRNG2", "stpRNG3", "stpRNG4", "stpRNG5"]:
            print(f"{symbol}: Ignored due to insufficient payout.")  
        else:
        
            quote = tick["tick"]["quote"]
            
            if state["skip_next_ticks64"] > 0:
                if state["skip_next_ticks64"] == 2:
                    print(f"{symbol}: First skipped tick {quote} - trade placement point")
                    if state["pending_trade64"] is not None:
                        trade_type = state["pending_trade64"]["trade_type"]
                        stake_amount = state["pending_trade64"]["stake_amount"]
                        print(f"{symbol}: Executing pending trade - {trade_type} with stake {stake_amount}")
                        await place_trades64(symbol, trade_type, stake_amount)
                        state["pending_trade64"] = None
                    state["current_candle_ticks64"] = [quote]
                    state["skip_next_ticks64"] = 1 
                elif state["skip_next_ticks64"] == 1:
                    print(f"{symbol}: Second skipped tick {quote} - stored as first tick of new candle")
                    state["current_candle_ticks64"] = [quote]
                    state["skip_next_ticks64"] = 0 
                return             
            
            if len(state["current_candle_ticks64"]) < CONFIG["CANDLE_DURATION64"] + 1:
                state["current_candle_ticks64"].append(quote)
            
            if len(state["current_candle_ticks64"]) == CONFIG["CANDLE_DURATION64"] + 1:
                print(f"{symbol}: Candle complete: {state['current_candle_ticks64']}")
                async with SYMBOL_LOCKS[symbol]:
                    await process_candle64(symbol)
                state["skip_next_ticks64"] = 2 
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")
        

async def detect_reversals64(symbol, last_candle_color64, second_last_candle_color64):
    """Detect isolated single reversals and update counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT64"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT64"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        current_reversal64 = (
            second_last_candle_color64 is not None and
            last_candle_color64 is not None and
            last_candle_color64 != second_last_candle_color64
        )

        if current_reversal64:
            state["reversal_count64"] += 1
            state["was_previous_reversal64"] = True
            print(f"{symbol}: Reversal detected. Count: {state['reversal_count64']}")

            if not state["is_sequence_starting_with_green64"] and not state["is_sequence_starting_with_red64"]:
                if second_last_candle_color64 == -1:
                    state["is_sequence_starting_with_green64"] = True
                    print(f"{symbol}: Green flag triggered")
                elif second_last_candle_color64 == 1:
                    state["is_sequence_starting_with_red64"] = True
                    print(f"{symbol}: Red flag triggered")

        else:
            if state["was_previous_reversal64"]:
                if state["reversal_count64"] == 1:
                    state["isolated_single_reversal_count64"] += 1
                    print(f"{symbol}: Isolated single reversal confirmed. Total: {state['isolated_single_reversal_count64']}")
                    if state["isolated_single_reversal_count64"] >= 21:
                        ACTIVE_BOT = "BOT64"
                        INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                        await activate_symbol(symbol)

                else:
                    prev_count64 = state["isolated_single_reversal_count64"]
                    state["isolated_single_reversal_count64"] = 0
                    if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count64 >= 21:
                        print(f"{symbol}: Active sequence completed (had {prev_count64} isolated single reversals). Releasing lock")
                        await reset_state()

            state["was_previous_reversal64"] = False
            state["reversal_count64"] = 0
            state["is_sequence_starting_with_green64"] = False
            state["is_sequence_starting_with_red64"] = False
            print(f"Reversal count reset for {symbol}")

    except Exception as e:
        print(f"Error detecting reversals for {symbol}: {e}")


async def process_candle64(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL 
    state = SYMBOL_STATES[symbol]["BOT64"]
    try:
        second_last_candle_color64 = (
            1 if state["last_candle_open64"] is not None and state["last_candle_close64"] is not None and state["last_candle_close64"] > state["last_candle_open64"] else
            (-1 if state["last_candle_open64"] is not None and state["last_candle_close64"] is not None and state["last_candle_close64"] < state["last_candle_open64"] else None)
        )
        last_candle_color64 = (
            1 if state["current_candle_ticks64"][0] is not None and state["current_candle_ticks64"][-1] > state["current_candle_ticks64"][0] else
            (-1 if state["current_candle_ticks64"][0] is not None and state["current_candle_ticks64"][-1] < state["current_candle_ticks64"][0] else None)
        )

        await detect_reversals64(symbol, last_candle_color64, second_last_candle_color64)

        if state["reversal_count64"] == 1:
            if state["isolated_single_reversal_count64"] == 21:
                if state["is_sequence_starting_with_green64"]:
                    state["trade_type64"] = "PUTE"
                    state["stake_amount64"] = 1
                    state["previous_stake_amount64"] = state["stake_amount64"]
                elif state["is_sequence_starting_with_red64"]:
                    state["trade_type64"] = "CALLE"
                    state["stake_amount64"] = 1
                    state["previous_stake_amount64"] = state["stake_amount64"]

            elif state["isolated_single_reversal_count64"] > 21:
                if state["is_sequence_starting_with_green64"]:
                    state["trade_type64"] = "PUTE"
                    state["stake_amount64"] = state["previous_stake_amount64"] * 2.1
                    state["previous_stake_amount64"] = state["stake_amount64"]
                elif state["is_sequence_starting_with_red64"]:
                    state["trade_type64"] = "CALLE"
                    state["stake_amount64"] = state["previous_stake_amount64"] * 2.1
                    state["previous_stake_amount64"] = state["stake_amount64"]
                    
        else:
            state["trade_type64"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type64"] in ["PUTE", "CALLE"] and
            state["stake_amount64"] > 0 and
            state["isolated_single_reversal_count64"] > state["last_executed_reversal_count64"]
        ):
            state["pending_trade64"] = {
                "trade_type": state["trade_type64"],
                "stake_amount": state["stake_amount64"]
            }
            state["last_executed_reversal_count64"] = state["isolated_single_reversal_count64"]
            print(f"Trade prepared for {symbol}: {state['trade_type64']} with stake: {state['stake_amount64']} (isolated_single_reversal_count: {state['isolated_single_reversal_count64']})")
        else:
            print(f"No trade prepared for {symbol} (trade_type: {state['trade_type64']}, stake: {state['stake_amount64']}, isolated_single_reversal_count: {state['isolated_single_reversal_count64']})")

        state["last_candle_open64"] = state["current_candle_ticks64"][0]
        state["last_candle_close64"] = state["current_candle_ticks64"][-1]

    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


async def place_trades64(symbol, trade_type64, stake_amount64):
    """Place trades using trade API."""
    try:
        proposal = await api.proposal({
            "proposal": 1,
            "amount": stake_amount64,
            "basis": "stake",
            "contract_type": trade_type64,
            "currency": "USD",
            "duration": 4,
            "duration_unit": "t",
            "symbol": symbol
        })
    except APIError as e:
        print(f"APIError while getting proposal for {symbol}: {e}. Skipping trade...")
        return
    except Exception as e:
        print(f"Unexpected error while getting proposal for {symbol}: {e}. Skipping trade...")
        return
        
    try:
        proposal_id = proposal.get("proposal", {}).get("id")
        if not proposal_id:
            print(f"No proposal ID found for {symbol}. Skipping trade...")
            return
        buy_response = await api.buy({
            "buy": proposal_id,
            "price": stake_amount64
        })
        print(f"Trade successfully placed via for {symbol} ({trade_type64}, ${stake_amount64})")  
    except APIError as e:
        print(f"APIError while buying contract for {symbol}: {e}. Skipping trade...")
    except Exception as e:
        print(f"Unexpected error while buying contract for {symbol}: {e}. Skipping trade...")


