async def handle_tick69(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT69"]
    try:
        
        quote = tick["tick"]["quote"]
        
        if state["skip_next_ticks69"] > 0:
            if state["skip_next_ticks69"] == 2:
                print(f"{symbol}: First skipped tick {quote} - trade placement point")
                if state["pending_trade69"] is not None:
                    trade_type = state["pending_trade69"]["trade_type"]
                    stake_amount = state["pending_trade69"]["stake_amount"]
                    print(f"{symbol}: Executing pending trade - {trade_type} with stake {stake_amount}")
                    await place_trades69(symbol, trade_type, stake_amount)
                    state["pending_trade69"] = None
                state["current_candle_ticks69"] = [quote]
                state["skip_next_ticks69"] = 1  
            elif state["skip_next_ticks69"] == 1:
                print(f"{symbol}: Second skipped tick {quote} - stored as first tick of new candle")
                state["current_candle_ticks69"] = [quote]
                state["skip_next_ticks69"] = 0  
            return
            
        if len(state["current_candle_ticks69"]) < CONFIG["CANDLE_DURATION69"] + 1:
            state["current_candle_ticks69"].append(quote)
            
        if len(state["current_candle_ticks69"]) == CONFIG["CANDLE_DURATION69"] + 1:
            print(f"{symbol}: Candle complete: {state['current_candle_ticks69']}")
            async with SYMBOL_LOCKS[symbol]:
                await process_candle69(symbol)
            state["skip_next_ticks69"] = 2 
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_non_reversals69(symbol, last_candle_color69, second_last_candle_color69):
    """Detect isolated multiple non reversals and update counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT69"]
    try:           
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT69"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        current_non_reversal69 = (
            second_last_candle_color69 is not None and
            last_candle_color69 is not None and
            last_candle_color69 == second_last_candle_color69
        )

        if current_non_reversal69:
            state["non_reversal_count69"] += 1
            state["was_previous_non_reversal69"] = True
            print(f"{symbol}: Non reversal detected. Count: {state['non_reversal_count69']}")

            if not state["is_sequence_starting_with_green69"] and not state["is_sequence_starting_with_red69"]:
                if second_last_candle_color69 == 1:
                    state["is_sequence_starting_with_green69"] = True
                    print(f"{symbol}: Green flag triggered")
                elif second_last_candle_color69 == -1:
                    state["is_sequence_starting_with_red69"] = True
                    print(f"{symbol}: Red flag triggered")

        else:
            if state["was_previous_non_reversal69"]:
                if state["non_reversal_count69"] > 1:
                    state["isolated_multiple_non_reversal_count69"] += 1
                    print(f"{symbol}: Isolated multiple non reversal confirmed. Total: {state['isolated_multiple_non_reversal_count69']}")
                   
                    if state["isolated_multiple_non_reversal_count69"] >= 21:
                        ACTIVE_BOT = "BOT69"
                        INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                        await activate_symbol(symbol)

                else:
                    prev_count69 = state["isolated_multiple_non_reversal_count69"]
                    state["isolated_multiple_non_reversal_count69"] = 0

                    if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count69 >= 21:
                        print(f"{symbol}: Active sequence completed (had {prev_count69} isolated multiple non reversals). Releasing lock")
                        await reset_state()

            state["was_previous_non_reversal69"] = False
            state["non_reversal_count69"] = 0
            state["is_sequence_starting_with_green69"] = False
            state["is_sequence_starting_with_red69"] = False

    except Exception as e:
        print(f"Error detecting non reversals for {symbol}: {e}")         


