def create_subscription_callback81(symbol):
    def callback(data):
        try:
            if "tick" in data:
                asyncio.ensure_future(handle_tick81(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick81(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT81"]
    try: 
        if symbol in ["stpRNG", "stpRNG2", "stpRNG3", "stpRNG4", "stpRNG5"]:
            print(f"{symbol}: Ignored due to insufficient payout.")  
        else:
        
            quote = tick["tick"]["quote"]
            
            if state["skip_next_ticks81"] > 0:
                if state["skip_next_ticks81"] == 3:
                    print(f"{symbol}: First skipped tick {quote} - to be ignored")
                    state["current_candle_ticks81"] = [quote]
                    state["skip_next_ticks81"] = 2 
                elif state["skip_next_ticks81"] == 2:
                    print(f"{symbol}: Second skipped tick {quote} - trade placement point")
                    if state["pending_trade81"] is not None:
                        trade_type = state["pending_trade81"]["trade_type"]
                        stake_amount = state["pending_trade81"]["stake_amount"]
                        print(f"{symbol}: Executing pending trade - {trade_type} with stake {stake_amount}")
                        await place_trades81(symbol, trade_type, stake_amount)
                        state["pending_trade81"] = None
                    state["current_candle_ticks81"] = [quote]
                    state["skip_next_ticks81"] = 1 
                elif state["skip_next_ticks81"] == 1:
                    print(f"{symbol}: Third skipped tick {quote} - stored as first tick of new candle")
                    state["current_candle_ticks81"] = [quote]
                    state["skip_next_ticks81"] = 0 
                return             
            
            if len(state["current_candle_ticks81"]) < CONFIG["CANDLE_DURATION81"] + 1:
                state["current_candle_ticks81"].append(quote)
            
            if len(state["current_candle_ticks81"]) == CONFIG["CANDLE_DURATION81"] + 1:
                print(f"{symbol}: Candle complete: {state['current_candle_ticks81']}")
                async with SYMBOL_LOCKS[symbol]:
                    await process_candle81(symbol)
                state["skip_next_ticks81"] = 3 
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_non_reversals81(symbol, last_candle_color81, second_last_candle_color81):
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT81"]
    try:   
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT81"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return
            
        if (
            second_last_candle_color81 is None
            or last_candle_color81 is None
            or last_candle_color81 != second_last_candle_color81
        ):
            prev_count81 = state["non_reversal_count81"]
            state["non_reversal_count81"] = 0
            state["is_sequence_starting_with_green81"] = False
            state["is_sequence_starting_with_red81"] = False
            print(f"Non_reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count81 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count81} non_reversals). Releasing global lock")
                await reset_state()
            return
        
        if not state["is_sequence_starting_with_green81"] and not state["is_sequence_starting_with_red81"]:
            if second_last_candle_color81 == 1:
                state["is_sequence_starting_with_green81"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color81 == -1:
                state["is_sequence_starting_with_red81"] = True
                print(f"{symbol}: Red flag triggered")
       
        if last_candle_color81 == second_last_candle_color81:
            if state["is_sequence_starting_with_green81"] or state["is_sequence_starting_with_red81"]:
                state["non_reversal_count81"] += 1
                print(f"{symbol}: Non_reversal count increased to {state['non_reversal_count81']}")
                if state["non_reversal_count81"] >= 21:
                    ACTIVE_BOT = "BOT81"
                    INACTIVE_BOT = [b for b in CONFIG["BOTS"] if b != ACTIVE_BOT]
                    await activate_symbol(symbol)
    
    except Exception as e:
        print(f"Error detecting non_reversals for {symbol}: {e}")


async def process_candle81(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL
    state = SYMBOL_STATES[symbol]["BOT81"]
    try:
        second_last_candle_color81 = (
            1 if state["last_candle_open81"] is not None and state["last_candle_close81"] is not None and state["last_candle_close81"] > state["last_candle_open81"] else
            (-1 if state["last_candle_open81"] is not None and state["last_candle_close81"] is not None and state["last_candle_close81"] < state["last_candle_open81"] else None)
        )
        last_candle_color81 = (
            1 if state["current_candle_ticks81"][0] is not None and state["current_candle_ticks81"][-1] > state["current_candle_ticks81"][0] else
            (-1 if state["current_candle_ticks81"][0] is not None and state["current_candle_ticks81"][-1] < state["current_candle_ticks81"][0] else None)
        )
      
        await detect_non_reversals81(symbol, last_candle_color81, second_last_candle_color81)
       
        if state["non_reversal_count81"] == 21:
            if state["is_sequence_starting_with_green81"]:
                state["trade_type81"] = "PUTE"
                state["stake_amount81"] = 1
                state["previous_stake_amount81"] = state["stake_amount81"]
            elif state["is_sequence_starting_with_red81"]:
                state["trade_type81"] = "CALLE"
                state["stake_amount81"] = 1
                state["previous_stake_amount81"] = state["stake_amount81"]
                
        elif state["non_reversal_count81"] > 21:
            if state["is_sequence_starting_with_green81"]:
                state["trade_type81"] = "PUTE"
                state["stake_amount81"] = state["previous_stake_amount81"] * 2.1
                state["previous_stake_amount81"] = state["stake_amount81"]
            elif state["is_sequence_starting_with_red81"]:
                state["trade_type81"] = "CALLE"
                state["stake_amount81"] = state["previous_stake_amount81"] * 2.1
                state["previous_stake_amount81"] = state["stake_amount81"]
                
        else:
            state["trade_type81"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type81"] in ["PUTE", "CALLE"] and
            state["stake_amount81"] > 0 and
            state["non_reversal_count81"] > state["last_executed_non_reversal_count81"]
        ):
            state["pending_trade81"] = {
                "trade_type": state["trade_type81"],
                "stake_amount": state["stake_amount81"]
            }
            state["last_executed_non_reversal_count81"] = state["non_reversal_count81"]
            print(f"Trade prepared for {symbol}: {state['trade_type81']} with stake: {state['stake_amount81']} (non_reversal_count: {state['non_reversal_count81']})")
        else:
            print(f"No trade prepared for {symbol} (trade_type: {state['trade_type81']}, stake: {state['stake_amount81']}, non_reversal_count: {state['non_reversal_count81']})")

        state["last_candle_open81"] = state["current_candle_ticks81"][0]
        state["last_candle_close81"] = state["current_candle_ticks81"][-1]
        
    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


