async def handle_tick83(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT83"]
    try:
        
        quote = tick["tick"]["quote"]
        
        if state["skip_next_ticks83"] > 0:
            if state["skip_next_ticks83"] == 3:   
                print(f"{symbol}: First skipped tick {quote} - to be ingnored")   
                state["current_candle_ticks83"] = [quote]
                state["skip_next_ticks83"] = 2  
            elif state["skip_next_ticks83"] == 2:
                print(f"{symbol}: Second skipped tick {quote} - trade placement point")
                if state["pending_trade83"] is not None:
                    trade_type = state["pending_trade83"]["trade_type"]
                    stake_amount = state["pending_trade83"]["stake_amount"]
                    print(f"{symbol}: Executing pending trade - {trade_type} with stake {stake_amount}")
                    await place_trades83(symbol, trade_type, stake_amount)
                    state["pending_trade83"] = None
                state["current_candle_ticks83"] = [quote]
                state["skip_next_ticks83"] = 1  
            elif state["skip_next_ticks83"] == 1:
                print(f"{symbol}: Third skipped tick {quote} - stored as first tick of new candle")
                state["current_candle_ticks83"] = [quote]
                state["skip_next_ticks83"] = 0  
            return
            
        if len(state["current_candle_ticks83"]) < CONFIG["CANDLE_DURATION83"] + 1:
            state["current_candle_ticks83"].append(quote)
            
        if len(state["current_candle_ticks83"]) == CONFIG["CANDLE_DURATION83"] + 1:
            print(f"{symbol}: Candle complete: {state['current_candle_ticks83']}")
            async with SYMBOL_LOCKS[symbol]:
                await process_candle83(symbol)
            state["skip_next_ticks83"] = 3 
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_non_reversals83(symbol, last_candle_color83, second_last_candle_color83):
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT83"]
    try:  
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT83"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return
            
        if (
            second_last_candle_color83 is None
            or last_candle_color83 is None
            or last_candle_color83 != second_last_candle_color83
        ):
            prev_count83 = state["non_reversal_count83"]
            state["non_reversal_count83"] = 0
            state["is_sequence_starting_with_green83"] = False
            state["is_sequence_starting_with_red83"] = False
            print(f"Non_reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count83 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count83} non_reversals). Releasing global lock")
                await reset_state()
            return
        
        if not state["is_sequence_starting_with_green83"] and not state["is_sequence_starting_with_red83"]:
            if second_last_candle_color83 == 1:
                state["is_sequence_starting_with_green83"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color83 == -1:
                state["is_sequence_starting_with_red83"] = True
                print(f"{symbol}: Red flag triggered")
       
        if last_candle_color83 == second_last_candle_color83:
            if state["is_sequence_starting_with_green83"] or state["is_sequence_starting_with_red83"]:
                state["non_reversal_count83"] += 1
                print(f"{symbol}: Non_reversal count increased to {state['non_reversal_count83']}")
                if state["non_reversal_count83"] >= 21:
                    ACTIVE_BOT = "BOT83"
                    INACTIVE_BOT = [b for b in CONFIG["BOTS"] if b != ACTIVE_BOT]
                    await activate_symbol(symbol)
    
    except Exception as e:
        print(f"Error detecting non_reversals for {symbol}: {e}")


async def process_candle83(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL
    state = SYMBOL_STATES[symbol]["BOT83"]
    try:
        second_last_candle_color83 = (
            1 if state["last_candle_open83"] is not None and state["last_candle_close83"] is not None and state["last_candle_close83"] > state["last_candle_open83"] else
            (-1 if state["last_candle_open83"] is not None and state["last_candle_close83"] is not None and state["last_candle_close83"] < state["last_candle_open83"] else None)
        )
        last_candle_color83 = (
            1 if state["current_candle_ticks83"][0] is not None and state["current_candle_ticks83"][-1] > state["current_candle_ticks83"][0] else
            (-1 if state["current_candle_ticks83"][0] is not None and state["current_candle_ticks83"][-1] < state["current_candle_ticks83"][0] else None)
        )
      
        await detect_non_reversals83(symbol, last_candle_color83, second_last_candle_color83)
       
        if state["non_reversal_count83"] == 21:
            if state["is_sequence_starting_with_green83"]:
                state["trade_type83"] = "PUTE"
                state["stake_amount83"] = 1
                state["previous_stake_amount83"] = state["stake_amount83"]
            elif state["is_sequence_starting_with_red83"]:
                state["trade_type83"] = "CALLE"
                state["stake_amount83"] = 1
                state["previous_stake_amount83"] = state["stake_amount83"]
                
        elif state["non_reversal_count83"] > 21:
            if state["is_sequence_starting_with_green83"]:
                state["trade_type83"] = "PUTE"
                state["stake_amount83"] = state["previous_stake_amount83"] * 2.1
                state["previous_stake_amount83"] = state["stake_amount83"]
            elif state["is_sequence_starting_with_red83"]:
                state["trade_type83"] = "CALLE"
                state["stake_amount83"] = state["previous_stake_amount83"] * 2.1
                state["previous_stake_amount83"] = state["stake_amount83"]
                
        else:
            state["trade_type83"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type83"] in ["PUTE", "CALLE"] and
            state["stake_amount83"] > 0 and
            state["non_reversal_count83"] > state["last_executed_non_reversal_count83"]
        ):
            state["pending_trade83"] = {
                "trade_type": state["trade_type83"],
                "stake_amount": state["stake_amount83"]
            }
            state["last_executed_non_reversal_count83"] = state["non_reversal_count83"]
            print(f"Trade prepared for {symbol}: {state['trade_type83']} with stake: {state['stake_amount83']} (non_reversal_count: {state['non_reversal_count83']})")
        else:
            print(f"No trade prepared for {symbol} (trade_type: {state['trade_type83']}, stake: {state['stake_amount83']}, non_reversal_count: {state['non_reversal_count83']})")

        state["last_candle_open83"] = state["current_candle_ticks83"][0]
        state["last_candle_close83"] = state["current_candle_ticks83"][-1]
        
    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


async def place_trades83(symbol, trade_type83, stake_amount83):
    """Place trades using trade API."""
    try:
        proposal = await api.proposal({
            "proposal": 1,
            "amount": stake_amount83,
            "basis": "stake",
            "contract_type": trade_type83,
            "currency": "USD",
            "duration": 3,
            "duration_unit": "t",
            "symbol": symbol
        })
    except APIError as e:
        print(f"APIError while getting proposal for {symbol}: {e}. Skipping trade...")
        return
    except Exception as e:
        print(f"Unexpected error while getting proposal for {symbol}: {e}. Skipping trade...")
        return
        
    try:
        proposal_id = proposal.get("proposal", {}).get("id")
        if not proposal_id:
            print(f"No proposal ID found for {symbol}. Skipping trade...")
            return
        buy_response = await api.buy({
            "buy": proposal_id,
            "price": stake_amount83
        })
        print(f"Trade successfully placed via for {symbol} ({trade_type83}, ${stake_amount83})")        
    except APIError as e:
        print(f"APIError while buying contract for {symbol}: {e}. Skipping trade...")
    except Exception as e:
        print(f"Unexpected error while buying contract for {symbol}: {e}. Skipping trade...")


