async def detect_reversals84(symbol, last_candle_color84, second_last_candle_color84):
    """Detect reversals and update reversal counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT84"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT84"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        if (
            second_last_candle_color84 is None
            or last_candle_color84 is None
            or last_candle_color84 == second_last_candle_color84
        ):
            prev_count84 = state["reversal_count84"]
            state["reversal_count84"] = 0
            state["is_sequence_starting_with_green84"] = False
            state["is_sequence_starting_with_red84"] = False
            print(f"Reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count84 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count84} reversals). Releasing global lock")
                await reset_state()
            return

        if not state["is_sequence_starting_with_green84"] and not state["is_sequence_starting_with_red84"]:
            if second_last_candle_color84 == -1:
                state["is_sequence_starting_with_green84"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color84 == 1:
                state["is_sequence_starting_with_red84"] = True
                print(f"{symbol}: Red flag triggered")

        if last_candle_color84 != second_last_candle_color84:
            if state["is_sequence_starting_with_green84"] or state["is_sequence_starting_with_red84"]:
                state["reversal_count84"] += 1
                print(f"{symbol}: Reversal count increased to {state['reversal_count84']}")
                if state["reversal_count84"] >= 21:
                    ACTIVE_BOT = "BOT84"
                    INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                    await activate_symbol(symbol)

    except Exception as e:
        print(f"Error detecting reversals for {symbol}: {e}")


async def process_candle84(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL 
    state = SYMBOL_STATES[symbol]["BOT84"]
    try:
        second_last_candle_color84 = (
            1 if state["last_candle_open84"] is not None and state["last_candle_close84"] is not None and state["last_candle_close84"] > state["last_candle_open84"] else
            (-1 if state["last_candle_open84"] is not None and state["last_candle_close84"] is not None and state["last_candle_close84"] < state["last_candle_open84"] else None)
        )
        last_candle_color84 = (
            1 if state["current_candle_ticks84"][0] is not None and state["current_candle_ticks84"][-1] > state["current_candle_ticks84"][0] else
            (-1 if state["current_candle_ticks84"][0] is not None and state["current_candle_ticks84"][-1] < state["current_candle_ticks84"][0] else None)
        )

        await detect_reversals84(symbol, last_candle_color84, second_last_candle_color84)

        if state["reversal_count84"] == 21:
            if state["is_sequence_starting_with_green84"]:
                state["trade_type84"] = "CALLE"
                state["stake_amount84"] = 1
                state["previous_stake_amount84"] = state["stake_amount84"]
            elif state["is_sequence_starting_with_red84"]:
                state["trade_type84"] = "PUTE"
                state["stake_amount84"] = 1
                state["previous_stake_amount84"] = state["stake_amount84"]
                
        elif state["reversal_count84"] > 21:
            if state["is_sequence_starting_with_green84"]:
                state["trade_type84"] = "CALLE" if state["reversal_count84"] % 2 == 1 else "PUTE"
                state["stake_amount84"] = state["previous_stake_amount84"] * 2.1
                state["previous_stake_amount84"] = state["stake_amount84"]
            elif state["is_sequence_starting_with_red84"]:
                state["trade_type84"] = "PUTE" if state["reversal_count84"] % 2 == 1 else "CALLE"
                state["stake_amount84"] = state["previous_stake_amount84"] * 2.1
                state["previous_stake_amount84"] = state["stake_amount84"]
                
        else:
            state["trade_type84"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type84"] in ["PUTE", "CALLE"] and
            state["stake_amount84"] > 0 and
            state["reversal_count84"] > state["last_executed_reversal_count84"]
        ):
            state["pending_trade84"] = {
                "trade_type": state["trade_type84"],
                "stake_amount": state["stake_amount84"]
            }
            state["last_executed_reversal_count84"] = state["reversal_count84"]
            print(f"Trade prepared for {symbol}: {state['trade_type84']} with stake: {state['stake_amount84']} (reversal_count: {state['reversal_count84']})")
        else:
            print(f"No trade prepared for {symbol} (trade_type: {state['trade_type84']}, stake: {state['stake_amount84']}, reversal_count: {state['reversal_count84']})")

        state["last_candle_open84"] = state["current_candle_ticks84"][0]
        state["last_candle_close84"] = state["current_candle_ticks84"][-1]

    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


