async def reset_state86():
    """Reset internal state for all symbols."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, INACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT, ACTIVATION_CANDIDATES, LAST_ACTIVATION_TIME
    try:
        for symbol in SYMBOL_STATES:
            state = SYMBOL_STATES[symbol]["BOT86"]
            state["last_candle_open86"] = None
            state["last_candle_close86"] = None
            state["current_candle_ticks86"] = []
            state["reversal_count86"] = 0
            state["is_sequence_starting_with_green86"] = False
            state["is_sequence_starting_with_red86"] = False
            state["trade_type86"] = ""
            state["stake_amount86"] = 0
            state["previous_stake_amount86"] = 0
            state["last_executed_reversal_count86"] = -1
            state["skip_next_ticks86"] = 0
            state["pending_trade86"] = None             
        GLOBAL_SEQUENCE_ACTIVE = False
        ACTIVE_SYMBOL = None
        ACTIVE_BOT = None
        INACTIVE_SYMBOL = None
        INACTIVE_BOT = None
        ACTIVATION_CANDIDATES = []
        LAST_ACTIVATION_TIME = None
        print("Bot86 state has been reset for all symbols.")
    except Exception as e:
        print(f"Error during reset_state86: {e}")


def create_subscription_callback86(symbol):
    def callback(data):
        try:
            if "tick" in data:
                asyncio.ensure_future(handle_tick86(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick86(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT86"]
    try: 
        if symbol in ["stpRNG", "stpRNG2", "stpRNG3", "stpRNG4", "stpRNG5"]:
            print(f"{symbol}: Ignored due to insufficient payout.")  
        else:
        
            quote = tick["tick"]["quote"]
            
            if state["skip_next_ticks86"] > 0:
                if state["skip_next_ticks86"] == 3:
                    print(f"{symbol}: First skipped tick {quote} - to be ignored")
                    state["current_candle_ticks86"] = [quote]
                    state["skip_next_ticks86"] = 2 
                elif state["skip_next_ticks86"] == 2:
                    print(f"{symbol}: Second skipped tick {quote} - trade placement point")
                    if state["pending_trade86"] is not None:
                        trade_type = state["pending_trade86"]["trade_type"]
                        stake_amount = state["pending_trade86"]["stake_amount"]
                        print(f"{symbol}: Executing pending trade - {trade_type} with stake {stake_amount}")
                        await place_trades86(symbol, trade_type, stake_amount)
                        state["pending_trade86"] = None
                    state["current_candle_ticks86"] = [quote]
                    state["skip_next_ticks86"] = 1 
                elif state["skip_next_ticks86"] == 1:
                    print(f"{symbol}: Third skipped tick {quote} - stored as first tick of new candle")
                    state["current_candle_ticks86"] = [quote]
                    state["skip_next_ticks86"] = 0 
                return             
            
            if len(state["current_candle_ticks86"]) < CONFIG["CANDLE_DURATION86"] + 1:
                state["current_candle_ticks86"].append(quote)
            
            if len(state["current_candle_ticks86"]) == CONFIG["CANDLE_DURATION86"] + 1:
                print(f"{symbol}: Candle complete: {state['current_candle_ticks86']}")
                async with SYMBOL_LOCKS[symbol]:
                    await process_candle86(symbol)
                state["skip_next_ticks86"] = 3 
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_reversals86(symbol, last_candle_color86, second_last_candle_color86):
    """Detect reversals and update reversal counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT86"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT86"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        if (
            second_last_candle_color86 is None
            or last_candle_color86 is None
            or last_candle_color86 == second_last_candle_color86
        ):
            prev_count86 = state["reversal_count86"]
            state["reversal_count86"] = 0
            state["is_sequence_starting_with_green86"] = False
            state["is_sequence_starting_with_red86"] = False
            print(f"Reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count86 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count86} reversals). Releasing global lock")
                await reset_state()
            return

        if not state["is_sequence_starting_with_green86"] and not state["is_sequence_starting_with_red86"]:
            if second_last_candle_color86 == -1:
                state["is_sequence_starting_with_green86"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color86 == 1:
                state["is_sequence_starting_with_red86"] = True
                print(f"{symbol}: Red flag triggered")

        if last_candle_color86 != second_last_candle_color86:
            if state["is_sequence_starting_with_green86"] or state["is_sequence_starting_with_red86"]:
                state["reversal_count86"] += 1
                print(f"{symbol}: Reversal count increased to {state['reversal_count86']}")
                if state["reversal_count86"] >= 21:
                    ACTIVE_BOT = "BOT86"
                    INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                    await activate_symbol(symbol)

    except Exception as e:
        print(f"Error detecting reversals for {symbol}: {e}")


async def process_candle86(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL 
    state = SYMBOL_STATES[symbol]["BOT86"]
    try:
        second_last_candle_color86 = (
            1 if state["last_candle_open86"] is not None and state["last_candle_close86"] is not None and state["last_candle_close86"] > state["last_candle_open86"] else
            (-1 if state["last_candle_open86"] is not None and state["last_candle_close86"] is not None and state["last_candle_close86"] < state["last_candle_open86"] else None)
        )
        last_candle_color86 = (
            1 if state["current_candle_ticks86"][0] is not None and state["current_candle_ticks86"][-1] > state["current_candle_ticks86"][0] else
            (-1 if state["current_candle_ticks86"][0] is not None and state["current_candle_ticks86"][-1] < state["current_candle_ticks86"][0] else None)
        )

        await detect_reversals86(symbol, last_candle_color86, second_last_candle_color86)

        if state["reversal_count86"] == 21:
            if state["is_sequence_starting_with_green86"]:
                state["trade_type86"] = "CALLE"
                state["stake_amount86"] = 1
                state["previous_stake_amount86"] = state["stake_amount86"]
            elif state["is_sequence_starting_with_red86"]:
                state["trade_type86"] = "PUTE"
                state["stake_amount86"] = 1
                state["previous_stake_amount86"] = state["stake_amount86"]
                
        elif state["reversal_count86"] > 21:
            if state["is_sequence_starting_with_green86"]:
                state["trade_type86"] = "CALLE" if state["reversal_count86"] % 2 == 1 else "PUTE"
                state["stake_amount86"] = state["previous_stake_amount86"] * 2.1
                state["previous_stake_amount86"] = state["stake_amount86"]
            elif state["is_sequence_starting_with_red86"]:
                state["trade_type86"] = "PUTE" if state["reversal_count86"] % 2 == 1 else "CALLE"
                state["stake_amount86"] = state["previous_stake_amount86"] * 2.1
                state["previous_stake_amount86"] = state["stake_amount86"]
                
        else:
            state["trade_type86"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type86"] in ["PUTE", "CALLE"] and
            state["stake_amount86"] > 0 and
            state["reversal_count86"] > state["last_executed_reversal_count86"]
        ):
            state["pending_trade86"] = {
                "trade_type": state["trade_type86"],
                "stake_amount": state["stake_amount86"]
            }
            state["last_executed_reversal_count86"] = state["reversal_count86"]
            print(f"Trade prepared for {symbol}: {state['trade_type86']} with stake: {state['stake_amount86']} (reversal_count: {state['reversal_count86']})")
        else:
            print(f"No trade prepared for {symbol} (trade_type: {state['trade_type86']}, stake: {state['stake_amount86']}, reversal_count: {state['reversal_count86']})")

        state["last_candle_open86"] = state["current_candle_ticks86"][0]
        state["last_candle_close86"] = state["current_candle_ticks86"][-1]

    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


