            state["non_reversal_count91"] = 0
            state["is_sequence_starting_with_green91"] = False
            state["is_sequence_starting_with_red91"] = False
            state["trade_type91"] = ""
            state["stake_amount91"] = 0
            state["previous_stake_amount91"] = 0
            state["last_executed_non_reversal_count91"] = -1
            state["skip_next_ticks91"] = 0
            state["pending_trade91"] = None            
