def create_subscription_callback91(symbol):
    def callback(data):
        try:
            if "tick" in data:
                asyncio.ensure_future(handle_tick91(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick91(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT91"]
    try: 
        if symbol in ["stpRNG", "stpRNG2", "stpRNG3", "stpRNG4", "stpRNG5"]:
            print(f"{symbol}: Ignored due to insufficient payout.")  
        else:
        
            quote = tick["tick"]["quote"]
            
            if state["skip_next_ticks91"] > 0:
                if state["skip_next_ticks91"] == 3:
                    print(f"{symbol}: First skipped tick {quote} - to be ignored")
                    state["current_candle_ticks91"] = [quote]
                    state["skip_next_ticks91"] = 2 
                elif state["skip_next_ticks91"] == 2:
                    print(f"{symbol}: Second skipped tick {quote} - trade placement point")
                    if state["pending_trade91"] is not None:
                        trade_type = state["pending_trade91"]["trade_type"]
                        stake_amount = state["pending_trade91"]["stake_amount"]
                        print(f"{symbol}: Executing pending trade - {trade_type} with stake {stake_amount}")
                        await place_trades91(symbol, trade_type, stake_amount)
                        state["pending_trade91"] = None
                    state["current_candle_ticks91"] = [quote]
                    state["skip_next_ticks91"] = 1 
                elif state["skip_next_ticks91"] == 1:
                    print(f"{symbol}: Third skipped tick {quote} - stored as first tick of new candle")
                    state["current_candle_ticks91"] = [quote]
                    state["skip_next_ticks91"] = 0 
                return             
            
            if len(state["current_candle_ticks91"]) < CONFIG["CANDLE_DURATION91"] + 1:
                state["current_candle_ticks91"].append(quote)
            
            if len(state["current_candle_ticks91"]) == CONFIG["CANDLE_DURATION91"] + 1:
                print(f"{symbol}: Candle complete: {state['current_candle_ticks91']}")
                async with SYMBOL_LOCKS[symbol]:
                    await process_candle91(symbol)
                state["skip_next_ticks91"] = 3 
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


