def create_subscription_callback93(symbol):
    def callback(data):
        try:
            if "tick" in data:
                asyncio.ensure_future(handle_tick93(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick93(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT93"]
    try:
        
        quote = tick["tick"]["quote"]
        
        if state["skip_next_ticks93"] > 0:
            if state["skip_next_ticks93"] == 3:   
                print(f"{symbol}: First skipped tick {quote} - to be ingnored")   
                state["current_candle_ticks93"] = [quote]
                state["skip_next_ticks93"] = 2  
            elif state["skip_next_ticks93"] == 2:
                print(f"{symbol}: Second skipped tick {quote} - trade placement point")
                if state["pending_trade93"] is not None:
                    trade_type = state["pending_trade93"]["trade_type"]
                    stake_amount = state["pending_trade93"]["stake_amount"]
                    print(f"{symbol}: Executing pending trade - {trade_type} with stake {stake_amount}")
                    await place_trades93(symbol, trade_type, stake_amount)
                    state["pending_trade93"] = None
                state["current_candle_ticks93"] = [quote]
                state["skip_next_ticks93"] = 1  
            elif state["skip_next_ticks93"] == 1:
                print(f"{symbol}: Third skipped tick {quote} - stored as first tick of new candle")
                state["current_candle_ticks93"] = [quote]
                state["skip_next_ticks93"] = 0  
            return
            
        if len(state["current_candle_ticks93"]) < CONFIG["CANDLE_DURATION93"] + 1:
            state["current_candle_ticks93"].append(quote)
            
        if len(state["current_candle_ticks93"]) == CONFIG["CANDLE_DURATION93"] + 1:
            print(f"{symbol}: Candle complete: {state['current_candle_ticks93']}")
            async with SYMBOL_LOCKS[symbol]:
                await process_candle93(symbol)
            state["skip_next_ticks93"] = 3 
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_non_reversals93(symbol, last_candle_color93, second_last_candle_color93):
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT93"]
    try:  
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT93"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return
            
        if (
            second_last_candle_color93 is None
            or last_candle_color93 is None
            or last_candle_color93 != second_last_candle_color93
        ):
            prev_count93 = state["non_reversal_count93"]
            state["non_reversal_count93"] = 0
            state["is_sequence_starting_with_green93"] = False
            state["is_sequence_starting_with_red93"] = False
            print(f"Non_reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count93 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count93} non_reversals). Releasing global lock")
                await reset_state()
            return
        
        if not state["is_sequence_starting_with_green93"] and not state["is_sequence_starting_with_red93"]:
            if second_last_candle_color93 == 1:
                state["is_sequence_starting_with_green93"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color93 == -1:
                state["is_sequence_starting_with_red93"] = True
                print(f"{symbol}: Red flag triggered")
       
        if last_candle_color93 == second_last_candle_color93:
            if state["is_sequence_starting_with_green93"] or state["is_sequence_starting_with_red93"]:
                state["non_reversal_count93"] += 1
                print(f"{symbol}: Non_reversal count increased to {state['non_reversal_count93']}")
                if state["non_reversal_count93"] >= 21:
                    ACTIVE_BOT = "BOT93"
                    INACTIVE_BOT = [b for b in CONFIG["BOTS"] if b != ACTIVE_BOT]
                    await activate_symbol(symbol)
    
    except Exception as e:
        print(f"Error detecting non_reversals for {symbol}: {e}")


async def process_candle93(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL
    state = SYMBOL_STATES[symbol]["BOT93"]
    try:
        second_last_candle_color93 = (
            1 if state["last_candle_open93"] is not None and state["last_candle_close93"] is not None and state["last_candle_close93"] > state["last_candle_open93"] else
            (-1 if state["last_candle_open93"] is not None and state["last_candle_close93"] is not None and state["last_candle_close93"] < state["last_candle_open93"] else None)
        )
        last_candle_color93 = (
            1 if state["current_candle_ticks93"][0] is not None and state["current_candle_ticks93"][-1] > state["current_candle_ticks93"][0] else
            (-1 if state["current_candle_ticks93"][0] is not None and state["current_candle_ticks93"][-1] < state["current_candle_ticks93"][0] else None)
        )
      
        await detect_non_reversals93(symbol, last_candle_color93, second_last_candle_color93)
       
        if state["non_reversal_count93"] == 21:
            if state["is_sequence_starting_with_green93"]:
                state["trade_type93"] = "PUTE"
                state["stake_amount93"] = 1
                state["previous_stake_amount93"] = state["stake_amount93"]
            elif state["is_sequence_starting_with_red93"]:
                state["trade_type93"] = "CALLE"
                state["stake_amount93"] = 1
                state["previous_stake_amount93"] = state["stake_amount93"]
                
        elif state["non_reversal_count93"] > 21:
            if state["is_sequence_starting_with_green93"]:
                state["trade_type93"] = "PUTE"
                state["stake_amount93"] = state["previous_stake_amount93"] * 2.1
                state["previous_stake_amount93"] = state["stake_amount93"]
            elif state["is_sequence_starting_with_red93"]:
                state["trade_type93"] = "CALLE"
                state["stake_amount93"] = state["previous_stake_amount93"] * 2.1
                state["previous_stake_amount93"] = state["stake_amount93"]
                
        else:
            state["trade_type93"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type93"] in ["PUTE", "CALLE"] and
            state["stake_amount93"] > 0 and
            state["non_reversal_count93"] > state["last_executed_non_reversal_count93"]
        ):
            state["pending_trade93"] = {
                "trade_type": state["trade_type93"],
                "stake_amount": state["stake_amount93"]
            }
            state["last_executed_non_reversal_count93"] = state["non_reversal_count93"]
            print(f"Trade prepared for {symbol}: {state['trade_type93']} with stake: {state['stake_amount93']} (non_reversal_count: {state['non_reversal_count93']})")
        else:
            print(f"No trade prepared for {symbol} (trade_type: {state['trade_type93']}, stake: {state['stake_amount93']}, non_reversal_count: {state['non_reversal_count93']})")

        state["last_candle_open93"] = state["current_candle_ticks93"][0]
        state["last_candle_close93"] = state["current_candle_ticks93"][-1]
        
    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


