async def detect_reversals96(symbol, last_candle_color96, second_last_candle_color96):
    """Detect reversals and update reversal counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT96"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT96"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        if (
            second_last_candle_color96 is None
            or last_candle_color96 is None
            or last_candle_color96 == second_last_candle_color96
        ):
            prev_count96 = state["reversal_count96"]
            state["reversal_count96"] = 0
            state["is_sequence_starting_with_green96"] = False
            state["is_sequence_starting_with_red96"] = False
            print(f"Reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count96 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count96} reversals). Releasing global lock")
                await reset_state()
            return

        if not state["is_sequence_starting_with_green96"] and not state["is_sequence_starting_with_red96"]:
            if second_last_candle_color96 == -1:
                state["is_sequence_starting_with_green96"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color96 == 1:
                state["is_sequence_starting_with_red96"] = True
                print(f"{symbol}: Red flag triggered")

        if last_candle_color96 != second_last_candle_color96:
            if state["is_sequence_starting_with_green96"] or state["is_sequence_starting_with_red96"]:
                state["reversal_count96"] += 1
                print(f"{symbol}: Reversal count increased to {state['reversal_count96']}")
                if state["reversal_count96"] >= 21:
                    ACTIVE_BOT = "BOT96"
                    INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                    await activate_symbol(symbol)

    except Exception as e:
        print(f"Error detecting reversals for {symbol}: {e}")


async def process_candle96(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL 
    state = SYMBOL_STATES[symbol]["BOT96"]
    try:
        second_last_candle_color96 = (
            1 if state["last_candle_open96"] is not None and state["last_candle_close96"] is not None and state["last_candle_close96"] > state["last_candle_open96"] else
            (-1 if state["last_candle_open96"] is not None and state["last_candle_close96"] is not None and state["last_candle_close96"] < state["last_candle_open96"] else None)
        )
        last_candle_color96 = (
            1 if state["current_candle_ticks96"][0] is not None and state["current_candle_ticks96"][-1] > state["current_candle_ticks96"][0] else
            (-1 if state["current_candle_ticks96"][0] is not None and state["current_candle_ticks96"][-1] < state["current_candle_ticks96"][0] else None)
        )

        await detect_reversals96(symbol, last_candle_color96, second_last_candle_color96)

        if state["reversal_count96"] == 21:
            if state["is_sequence_starting_with_green96"]:
                state["trade_type96"] = "CALLE"
                state["stake_amount96"] = 1
                state["previous_stake_amount96"] = state["stake_amount96"]
            elif state["is_sequence_starting_with_red96"]:
                state["trade_type96"] = "PUTE"
                state["stake_amount96"] = 1
                state["previous_stake_amount96"] = state["stake_amount96"]
                
        elif state["reversal_count96"] > 21:
            if state["is_sequence_starting_with_green96"]:
                state["trade_type96"] = "CALLE" if state["reversal_count96"] % 2 == 1 else "PUTE"
                state["stake_amount96"] = state["previous_stake_amount96"] * 2.1
                state["previous_stake_amount96"] = state["stake_amount96"]
            elif state["is_sequence_starting_with_red96"]:
                state["trade_type96"] = "PUTE" if state["reversal_count96"] % 2 == 1 else "CALLE"
                state["stake_amount96"] = state["previous_stake_amount96"] * 2.1
                state["previous_stake_amount96"] = state["stake_amount96"]
                
        else:
            state["trade_type96"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type96"] in ["PUTE", "CALLE"] and
            state["stake_amount96"] > 0 and
            state["reversal_count96"] > state["last_executed_reversal_count96"]
        ):
            state["pending_trade96"] = {
                "trade_type": state["trade_type96"],
                "stake_amount": state["stake_amount96"]
            }
            state["last_executed_reversal_count96"] = state["reversal_count96"]
            print(f"Trade prepared for {symbol}: {state['trade_type96']} with stake: {state['stake_amount96']} (reversal_count: {state['reversal_count96']})")
        else:
            print(f"No trade prepared for {symbol} (trade_type: {state['trade_type96']}, stake: {state['stake_amount96']}, reversal_count: {state['reversal_count96']})")

        state["last_candle_open96"] = state["current_candle_ticks96"][0]
        state["last_candle_close96"] = state["current_candle_ticks96"][-1]

    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


