def create_subscription_callback98(symbol):
    def callback(data):
        try:
            if "tick" in data:
                asyncio.ensure_future(handle_tick98(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick98(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT98"]
    try:
        
        quote = tick["tick"]["quote"]
        
        if state["skip_next_ticks98"] > 0:
            if state["skip_next_ticks98"] == 3:   
                print(f"{symbol}: First skipped tick {quote} - to be ingnored")   
                state["current_candle_ticks98"] = [quote]
                state["skip_next_ticks98"] = 2  
            elif state["skip_next_ticks98"] == 2:
                print(f"{symbol}: Second skipped tick {quote} - trade placement point")
                if state["pending_trade98"] is not None:
                    trade_type = state["pending_trade98"]["trade_type"]
                    stake_amount = state["pending_trade98"]["stake_amount"]
                    print(f"{symbol}: Executing pending trade - {trade_type} with stake {stake_amount}")
                    await place_trades98(symbol, trade_type, stake_amount)
                    state["pending_trade98"] = None
                state["current_candle_ticks98"] = [quote]
                state["skip_next_ticks98"] = 1  
            elif state["skip_next_ticks98"] == 1:
                print(f"{symbol}: Third skipped tick {quote} - stored as first tick of new candle")
                state["current_candle_ticks98"] = [quote]
                state["skip_next_ticks98"] = 0  
            return
            
        if len(state["current_candle_ticks98"]) < CONFIG["CANDLE_DURATION98"] + 1:
            state["current_candle_ticks98"].append(quote)
            
        if len(state["current_candle_ticks98"]) == CONFIG["CANDLE_DURATION98"] + 1:
            print(f"{symbol}: Candle complete: {state['current_candle_ticks98']}")
            async with SYMBOL_LOCKS[symbol]:
                await process_candle98(symbol)
            state["skip_next_ticks98"] = 3 
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_reversals98(symbol, last_candle_color98, second_last_candle_color98):
    """Detect reversals and update reversal counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT98"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT98"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        if (
            second_last_candle_color98 is None
            or last_candle_color98 is None
            or last_candle_color98 == second_last_candle_color98
        ):
            prev_count98 = state["reversal_count98"]
            state["reversal_count98"] = 0
            state["is_sequence_starting_with_green98"] = False
            state["is_sequence_starting_with_red98"] = False
            print(f"Reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count98 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count98} reversals). Releasing global lock")
                await reset_state()
            return

        if not state["is_sequence_starting_with_green98"] and not state["is_sequence_starting_with_red98"]:
            if second_last_candle_color98 == -1:
                state["is_sequence_starting_with_green98"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color98 == 1:
                state["is_sequence_starting_with_red98"] = True
                print(f"{symbol}: Red flag triggered")

        if last_candle_color98 != second_last_candle_color98:
            if state["is_sequence_starting_with_green98"] or state["is_sequence_starting_with_red98"]:
                state["reversal_count98"] += 1
                print(f"{symbol}: Reversal count increased to {state['reversal_count98']}")
                if state["reversal_count98"] >= 21:
                    ACTIVE_BOT = "BOT98"
                    INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                    await activate_symbol(symbol)

    except Exception as e:
        print(f"Error detecting reversals for {symbol}: {e}")


