async def reset_state100():
    """Reset internal state for all symbols."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, INACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT, ACTIVATION_CANDIDATES, LAST_ACTIVATION_TIME
    try:
        for symbol in SYMBOL_STATES:
            state = SYMBOL_STATES[symbol]["BOT100"]
            state["last_candle_open100"] = None
            state["last_candle_close100"] = None
            state["current_candle_ticks100"] = []
            state["reversal_count100"] = 0
            state["is_sequence_starting_with_green100"] = False
            state["is_sequence_starting_with_red100"] = False
            state["trade_type100"] = ""
            state["stake_amount100"] = 0
            state["previous_stake_amount100"] = 0
            state["last_executed_reversal_count100"] = -1
            state["skip_next_ticks100"] = 0
            state["pending_trade100"] = None            
        GLOBAL_SEQUENCE_ACTIVE = False
        ACTIVE_SYMBOL = None
        ACTIVE_BOT = None
        INACTIVE_SYMBOL = None
        INACTIVE_BOT = None
        ACTIVATION_CANDIDATES = []
        LAST_ACTIVATION_TIME = None
        print("Bot100 state has been reset for all symbols.")
    except Exception as e:
        print(f"Error during reset_state100: {e}")


def create_subscription_callback100(symbol):
    def callback(data):
        try:
            if "tick" in data:
                asyncio.ensure_future(handle_tick100(symbol, data))
        except Exception as e:
            print(f"Error in subscription callback for {symbol}: {e}")
    return callback


async def handle_tick100(symbol, tick):
    """Handle incoming tick data for a specific symbol."""
    state = SYMBOL_STATES[symbol]["BOT100"]
    try:
        
        quote = tick["tick"]["quote"]
        
        if state["skip_next_ticks100"] > 0:
            if state["skip_next_ticks100"] == 3:   
                print(f"{symbol}: First skipped tick {quote} - to be ingnored")   
                state["current_candle_ticks100"] = [quote]
                state["skip_next_ticks100"] = 2  
            elif state["skip_next_ticks100"] == 2:
                print(f"{symbol}: Second skipped tick {quote} - trade placement point")
                if state["pending_trade100"] is not None:
                    trade_type = state["pending_trade100"]["trade_type"]
                    stake_amount = state["pending_trade100"]["stake_amount"]
                    print(f"{symbol}: Executing pending trade - {trade_type} with stake {stake_amount}")
                    await place_trades100(symbol, trade_type, stake_amount)
                    state["pending_trade100"] = None
                state["current_candle_ticks100"] = [quote]
                state["skip_next_ticks100"] = 1  
            elif state["skip_next_ticks100"] == 1:
                print(f"{symbol}: Third skipped tick {quote} - stored as first tick of new candle")
                state["current_candle_ticks100"] = [quote]
                state["skip_next_ticks100"] = 0  
            return
            
        if len(state["current_candle_ticks100"]) < CONFIG["CANDLE_DURATION100"] + 1:
            state["current_candle_ticks100"].append(quote)
            
        if len(state["current_candle_ticks100"]) == CONFIG["CANDLE_DURATION100"] + 1:
            print(f"{symbol}: Candle complete: {state['current_candle_ticks100']}")
            async with SYMBOL_LOCKS[symbol]:
                await process_candle100(symbol)
            state["skip_next_ticks100"] = 3 
            
    except Exception as e:
        print(f"Error handling tick data for {symbol}: {e}")


async def detect_reversals100(symbol, last_candle_color100, second_last_candle_color100):
    """Detect reversals and update reversal counts for a specific symbol."""
    global GLOBAL_SEQUENCE_ACTIVE, ACTIVE_SYMBOL, ACTIVE_BOT, INACTIVE_BOT
    state = SYMBOL_STATES[symbol]["BOT100"]
    try:
        if GLOBAL_SEQUENCE_ACTIVE and (symbol != ACTIVE_SYMBOL or ACTIVE_BOT != "BOT100"):
            print(f"{symbol}: Global sequence active on {ACTIVE_SYMBOL}. Skipping further processing.")
            return

        if (
            second_last_candle_color100 is None
            or last_candle_color100 is None
            or last_candle_color100 == second_last_candle_color100
        ):
            prev_count100 = state["reversal_count100"]
            state["reversal_count100"] = 0
            state["is_sequence_starting_with_green100"] = False
            state["is_sequence_starting_with_red100"] = False
            print(f"Reversal count reset for {symbol}")
            if GLOBAL_SEQUENCE_ACTIVE and ACTIVE_SYMBOL == symbol and prev_count100 >= 21:
                print(f"{symbol}: Active sequence completed (had {prev_count100} reversals). Releasing global lock")
                await reset_state()
            return

        if not state["is_sequence_starting_with_green100"] and not state["is_sequence_starting_with_red100"]:
            if second_last_candle_color100 == -1:
                state["is_sequence_starting_with_green100"] = True
                print(f"{symbol}: Green flag triggered")
            elif second_last_candle_color100 == 1:
                state["is_sequence_starting_with_red100"] = True
                print(f"{symbol}: Red flag triggered")

        if last_candle_color100 != second_last_candle_color100:
            if state["is_sequence_starting_with_green100"] or state["is_sequence_starting_with_red100"]:
                state["reversal_count100"] += 1
                print(f"{symbol}: Reversal count increased to {state['reversal_count100']}")
                if state["reversal_count100"] >= 21:
                    ACTIVE_BOT = "BOT100"
                    INACTIVE_BOT = [s for s in CONFIG["BOTS"] if s != ACTIVE_BOT]
                    await activate_symbol(symbol)

    except Exception as e:
        print(f"Error detecting reversals for {symbol}: {e}")


async def process_candle100(symbol):
    """Process completed candlestick for a given symbol."""
    global INACTIVE_SYMBOL
    state = SYMBOL_STATES[symbol]["BOT100"]
    try:
        second_last_candle_color100 = (
            1 if state["last_candle_open100"] is not None and state["last_candle_close100"] is not None and state["last_candle_close100"] > state["last_candle_open100"] else
            (-1 if state["last_candle_open100"] is not None and state["last_candle_close100"] is not None and state["last_candle_close100"] < state["last_candle_open100"] else None)
        )
        last_candle_color100 = (
            1 if state["current_candle_ticks100"][0] is not None and state["current_candle_ticks100"][-1] > state["current_candle_ticks100"][0] else
            (-1 if state["current_candle_ticks100"][0] is not None and state["current_candle_ticks100"][-1] < state["current_candle_ticks100"][0] else None)
        )

        await detect_reversals100(symbol, last_candle_color100, second_last_candle_color100)

        if state["reversal_count100"] == 21:
            if state["is_sequence_starting_with_green100"]:
                state["trade_type100"] = "CALLE"
                state["stake_amount100"] = 1
                state["previous_stake_amount100"] = state["stake_amount100"]
            elif state["is_sequence_starting_with_red100"]:
                state["trade_type100"] = "PUTE"
                state["stake_amount100"] = 1
                state["previous_stake_amount100"] = state["stake_amount100"]
                
        elif state["reversal_count100"] > 21:
            if state["is_sequence_starting_with_green100"]:
                state["trade_type100"] = "CALLE" if state["reversal_count100"] % 2 == 1 else "PUTE"
                state["stake_amount100"] = state["previous_stake_amount100"] * 2.1
                state["previous_stake_amount100"] = state["stake_amount100"]
            elif state["is_sequence_starting_with_red100"]:
                state["trade_type100"] = "PUTE" if state["reversal_count100"] % 2 == 1 else "CALLE"
                state["stake_amount100"] = state["previous_stake_amount100"] * 2.1
                state["previous_stake_amount100"] = state["stake_amount100"]
                
        else:
            state["trade_type100"] = ""

        if (
            (INACTIVE_SYMBOL is not None and symbol not in INACTIVE_SYMBOL) and
            state["trade_type100"] in ["PUTE", "CALLE"] and
            state["stake_amount100"] > 0 and
            state["reversal_count100"] > state["last_executed_reversal_count100"]
        ):
            state["pending_trade100"] = {
                "trade_type": state["trade_type100"],
                "stake_amount": state["stake_amount100"]
            }
            state["last_executed_reversal_count100"] = state["reversal_count100"]
            print(f"Trade prepared for {symbol}: {state['trade_type100']} with stake: {state['stake_amount100']} (reversal_count: {state['reversal_count100']})")
        else:
            print(f"No trade prepared for {symbol} (trade_type: {state['trade_type100']}, stake: {state['stake_amount100']}, reversal_count: {state['reversal_count100']})")

        state["last_candle_open100"] = state["current_candle_ticks100"][0]
        state["last_candle_close100"] = state["current_candle_ticks100"][-1]

    except Exception as e:
        print(f"Error processing candle for {symbol}: {e}")


async def place_trades100(symbol, trade_type100, stake_amount100):
    """Place trades using trade API."""
    try:   
        proposal = await api.proposal({
            "proposal": 1,
            "amount": stake_amount100,
            "basis": "stake",
            "contract_type": trade_type100,
            "currency": "USD",
            "duration": 1,
            "duration_unit": "t",
            "symbol": symbol
        })
    except APIError as e:
        print(f"APIError while getting proposal for {symbol}: {e}. Skipping trade...")
        return
    except Exception as e:
        print(f"Unexpected error while getting proposal for {symbol}: {e}. Skipping trade...")
        return
        
    try:
        proposal_id = proposal.get("proposal", {}).get("id")
        if not proposal_id:
            print(f"No proposal ID found for {symbol}. Skipping trade...")
            return
        buy_response = await api.buy({
            "buy": proposal_id,
            "price": stake_amount100
        })
        print(f"Trade successfully placed for {symbol} ({trade_type100}, ${stake_amount100})") 
    except APIError as e:
        print(f"APIError while buying contract for {symbol}: {e}. Skipping trade...")
    except Exception as e:
        print(f"Unexpected error while buying contract for {symbol}: {e}. Skipping trade...")                        
        
        
